// ── Reconciliation flow ───────────────────────────────────────────────────────
function ReconciliationFlow({ accountName, onClose, showResults = false, allResolved = false, isCleanReconcile = false, onUploadStatement, reconciledDate = null, reconciledMatchedStr = null, accountStatus = null, existingStatement = null, reconciledStatuses = {}, reconciledCounts = {}, selectedPeriod = "April 2026", initialResolvedCards = null, initialIgnoredCards = null, onAddComment }) {
  const accounts = [
    "Lloyds Bank - Business", "Lloyds Bank - Operations GBP",
    "HSBC - Business Transactions", "Barclays - Operations",
    "American Express OP GBP", "Mastercard Business",
  ];
  const isPicker = accountName === "__picker__";
  const [selectedAccount, setSelectedAccount] = useState(isPicker ? null : accountName);
  const [accountSelected, setAccountSelected] = useState(!isPicker); // true when account already known or user picks one
  const [highlightedAccount, setHighlightedAccount] = useState(isPicker ? 0 : -1); // keyboard cursor index in the picker
  const effectiveIsCleanReconcile = isCleanReconcile || (isPicker && selectedAccount === "Lloyds Bank - Operations GBP");
  const effectiveAccountName = selectedAccount || accountName;
  const [dropdownOpen, setDropdownOpen]       = useState(false);
  const [inputValue, setInputValue]           = useState("");
  const [isAtBottom, setIsAtBottom]           = useState(true);
  const [uploadedFiles, setUploadedFiles]     = useState(showResults ? [{ name: existingStatement?.fileName || "bank-statement.pdf", type: "application/pdf" }] : existingStatement ? [{ name: existingStatement.fileName, type: existingStatement.fileName?.endsWith(".csv") ? "text/csv" : "application/pdf" }] : null);
  const [previewUrl, setPreviewUrl]           = useState(null);
  const [prepDone, setPrepDone]               = useState(showResults || !!existingStatement);
  const [startClicked, setStartClicked]       = useState(showResults);
  const [highlightedStart, setHighlightedStart] = useState(0);
  const [stepStatuses, setStepStatuses]       = useState(showResults ? RECONCILIATION_STEPS.map(() => "done") : []);
  const [stepSubtexts, setStepSubtexts]       = useState(showResults ? RECONCILIATION_STEPS.map(s => s.subtext || "") : []);
  const [visibleSteps, setVisibleSteps]       = useState(showResults ? RECONCILIATION_STEPS.length : 0);
  const [stepsPopulated, setStepsPopulated]   = useState(showResults);
  const [reconciliationCollapsed, setReconciliationCollapsed] = useState(showResults);
  const [userMessages, setUserMessages]       = useState([]);
  const [feedProceedChoice, setFeedProceedChoice] = useState(showResults ? "upload" : null);
  const [csvConverting, setCsvConverting]     = useState(false);
  const [csvConvertDone, setCsvConvertDone]   = useState(false);
  const [reuploadPhase, setReuploadPhase]     = useState(false);
  const [replaceStatementMode, setReplaceStatementMode] = useState(false);
  const [resultsVisible, setResultsVisible]   = useState(showResults);
  const [canvasReady, setCanvasReady]         = useState(showResults);
  const [boxesOpen, setBoxesOpen]             = useState(false);
  const [creditCardBannerDismissed, setCreditCardBannerDismissed] = useState(false);
  const addStatementInputRef = useRef(null);
  const [chatWidth, setChatWidth]             = useState(400);
  const [isDragging, setIsDragging]           = useState(false);
  const [allDocsOpen, setAllDocsOpen]             = useState(false);
  const [preselectedDocs, setPreselectedDocs]     = useState(null);
  const [spendMoneySidebar, setSpendMoneySidebar] = useState(null);
  const chatScrollRef = useRef(null);
  const chatEndRef    = useRef(null);
  const dropdownRef   = useRef(null);
  const stepRowRefs   = useRef([]);
  const [batchDraftSidebar, setBatchDraftSidebar] = useState(null);
  const [isClosing, setIsClosing] = useState(false);
  const ACCOUNT_TOTAL_SUGGESTIONS = {
    "Lloyds Bank - Business": 8,
    "HSBC - Business Transactions": 58,
    "Barclays - Operations": 5,
    "American Express OP GBP": 8,
    "Mastercard Business": 3,
  };
  const totalSuggestions = ACCOUNT_TOTAL_SUGGESTIONS[accountName] ?? 8;
  const allResolvedSet = allResolved ? new Set(Array.from({ length: totalSuggestions }, (_, i) => i)) : new Set();
  const [resolvedCards, setResolvedCards] = useState(initialResolvedCards ? new Set(initialResolvedCards) : allResolvedSet);
  const [ignoredCards, setIgnoredCards] = useState(initialIgnoredCards ? new Set(initialIgnoredCards) : new Set());
  const [markCompleteDrawerOpen, setMarkCompleteDrawerOpen] = useState(false);
  const [markCompleteComment, setMarkCompleteComment] = useState("");
  const [periodChosen, setPeriodChosen] = useState(showResults ? { key: "full", label: "Full accounting period", sub: "Apr 1 – Apr 30" } : null);
  const [highlightedPeriod, setHighlightedPeriod] = useState(0);
  const [changeFlow, setChangeFlow] = useState(false);
  const cardOptions = [
    { key: "jeremy",  label: "Jeremy Smith **** 1039" },
    { key: "anna",    label: "Anna Larson **** 1054"  },
    { key: "all",     label: "All statement transactions" },
  ];
  const [cardChosen, setCardChosen] = useState(showResults ? cardOptions[0] : null);
  const [highlightedCard, setHighlightedCard] = useState(0);
  const [auditLogOpen, setAuditLogOpen] = useState(false);
  const [auditEntries, setAuditEntries] = useState([]);
  const auditCounterRef = React.useRef(0);
  const addAuditEntryRef = React.useRef(null);
  const addAuditEntry = (action, details, color = "#05A105") => {
    const now = new Date();
    const time = now.getHours().toString().padStart(2,"0") + ":" + now.getMinutes().toString().padStart(2,"0");
    const id = ++auditCounterRef.current;
    setAuditEntries(prev => [{ id, time, color, action, actor: "Laura Bennett", details }, ...prev]);
  };
  addAuditEntryRef.current = addAuditEntry;
  const [toast, setToast] = useState(null);

  // Drag handler for resizable chat panel
  const handleDragStart = (e) => {
    e.preventDefault();
    setIsDragging(true);
    const startX = e.clientX;
    const startWidth = chatWidth;

    const onMouseMove = (e) => {
      const newWidth = Math.max(280, Math.min(700, startWidth + (e.clientX - startX)));
      setChatWidth(newWidth);
    };

    const onMouseUp = () => {
      setIsDragging(false);
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);
      document.body.style.cursor = "";
      document.body.style.userSelect = "";
    };

    document.body.style.cursor = "col-resize";
    document.body.style.userSelect = "none";
    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
  };

  const reconciliationComplete = stepStatuses.length > 0 && stepStatuses.every(s => s === "done");

  useEffect(() => {
    if (reconciliationComplete) setResultsVisible(true);
  }, [reconciliationComplete]);

  // Escape key — closes any open overlay first, then goes back to account overview
  useEffect(() => {
    const onKeyDown = (e) => {
      if (e.key !== "Escape") return;
      if (allDocsOpen)        { setAllDocsOpen(false); return; }
      if (spendMoneySidebar)  { setSpendMoneySidebar(null); return; }
      if (batchDraftSidebar)  { setBatchDraftSidebar(null); return; }
      const remaining = Math.max(0, totalSuggestions - resolvedCards.size - ignoredCards.size);
      onClose(canvasReady, (resolvedCards.size + ignoredCards.size) >= totalSuggestions, effectiveAccountName, remaining, resolvedCards, ignoredCards);
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [allDocsOpen, spendMoneySidebar, batchDraftSidebar, canvasReady, resolvedCards, ignoredCards, totalSuggestions, effectiveAccountName]);

  // Delay canvas content until panel has slid in
  useEffect(() => {
    if (!resultsVisible) return;
    if (showResults) { setCanvasReady(true); return; }
    setCanvasReady(false);
    const t1 = setTimeout(() => setCanvasReady(true), 3200);
    return () => { clearTimeout(t1); };
  }, [resultsVisible]);

  useEffect(() => {
    if (stepStatuses.length > 0 && stepStatuses.every(s => s === "done")) {
      const t = setTimeout(() => setReconciliationCollapsed(true), 600);
      return () => clearTimeout(t);
    }
  }, [stepStatuses]);

  const handleRestart = () => {
    // Trigger canvas slide-out and chat expand simultaneously
    setResultsVisible(false);
    // Reset chat state immediately
    setUploadedFiles(null);
    setPreviewUrl(null);
    setPrepDone(false);
    setStartClicked(false);
    setStepStatuses([]);
    setStepSubtexts([]);
    setUserMessages([]);
    setReuploadPhase(false);
    setFeedProceedChoice(null);
    setCsvConverting(false);
    setCsvConvertDone(false);
    setInputValue("");
    // Unmount canvas content only after the slide-out animation finishes (720ms)
    setTimeout(() => setCanvasReady(false), 720);
  };

  const handleAddStatementFile = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    e.target.value = "";
    const newFiles = [...(uploadedFiles || []), { name: file.name, type: file.type }];
    // Restart reconciliation with the combined files
    setResultsVisible(false);
    setPreviewUrl(null);
    setPrepDone(false);
    setStartClicked(false);
    setStepStatuses([]);
    setStepSubtexts([]);
    setUserMessages([]);
    setReuploadPhase(false);
    setFeedProceedChoice("upload");
    setInputValue("");
    setCreditCardBannerDismissed(false);
    setTimeout(() => {
      setCanvasReady(false);
      setUploadedFiles(newFiles);
    }, 50);
  };

  const handleReplaceStatement = () => {
    setReplaceStatementMode(true);
    setResultsVisible(false);
    setCanvasReady(false);
    setBoxesOpen(false);
  };

  const handleSend = () => {
    const msg = inputValue.trim();
    if (!msg) return;
    setUserMessages(prev => [...prev, msg]);
    setInputValue("");
    setUploadedFile(null);
    setPreviewUrl(null);
    setPrepDone(false);
    setStartClicked(false);
    setStepStatuses([]);
    setStepSubtexts([]);
    setReuploadPhase(true);
  };

  // Phase 1: reveal steps one by one
  useEffect(() => {
    if (!startClicked || showResults) return;
    const REVEAL_INTERVAL = 600;
    const timers = [];
    RECONCILIATION_STEPS.forEach((_, i) => {
      timers.push(setTimeout(() => {
        setVisibleSteps(i + 1);
      }, i * REVEAL_INTERVAL));
    });
    const totalRevealTime = (RECONCILIATION_STEPS.length - 1) * REVEAL_INTERVAL + 450;
    timers.push(setTimeout(() => setStepsPopulated(true), totalRevealTime));
    return () => timers.forEach(clearTimeout);
  }, [startClicked]);

  // Phase 2: run spinner through steps once all are populated
  useEffect(() => {
    if (!stepsPopulated || showResults) return;
    setStepStatuses(RECONCILIATION_STEPS.map((_, i) => i === 0 ? "active" : "pending"));
    setStepSubtexts(RECONCILIATION_STEPS.map(() => false));
    let cumulative = 0;
    const timers = [];
    RECONCILIATION_STEPS.forEach((step, i) => {
      cumulative += step.duration;
      if (step.subtext) {
        timers.push(setTimeout(() => {
          setStepSubtexts(prev => { const next = [...prev]; next[i] = true; return next; });
        }, cumulative - 400));
      }
      timers.push(setTimeout(() => {
        setStepStatuses(prev => {
          const next = [...prev];
          next[i] = "done";
          if (i + 1 < RECONCILIATION_STEPS.length) next[i + 1] = "active";
          return next;
        });
      }, cumulative));
    });
    return () => timers.forEach(clearTimeout);
  }, [stepsPopulated]);

  // After file is selected, wait 2.2s then start AI response (normal flow only)
  useEffect(() => {
    if (!uploadedFiles || showResults || feedProceedChoice === "convert") return;
    const t = setTimeout(() => setPrepDone(true), 2200);
    return () => clearTimeout(t);
  }, [uploadedFiles]);

  // Inject spin keyframe once
  useEffect(() => {
    if (document.getElementById("_spin_kf")) return;
    const s = document.createElement("style");
    s.id = "_spin_kf";
    s.textContent = "@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }";
    document.head.appendChild(s);
  }, []);

  // CSV conversion flow — starts after file uploaded in convert mode
  useEffect(() => {
    if (feedProceedChoice !== "convert" || !uploadedFiles || csvConvertDone) return;
    const t1 = setTimeout(() => setCsvConverting(true), 600);
    const t2 = setTimeout(() => { setCsvConverting(false); setCsvConvertDone(true); }, 3200);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [uploadedFiles, feedProceedChoice]);

  const handleFileSelected = (fileOrDocs) => {
    const files = Array.isArray(fileOrDocs) ? fileOrDocs : [fileOrDocs];
    setUploadedFiles(files);
    if (files.length === 1 && files[0].type?.startsWith("image/")) {
      setPreviewUrl(URL.createObjectURL(files[0]));
    }
    const now = new Date();
    const dateStr = now.toLocaleDateString("en-GB", { day: "numeric", month: "short" });
    onUploadStatement?.(selectedAccount, { fileName: files[0].name, date: dateStr });
  };

  // Thinking delay — show spinner for ~3s before first response types
  const [thinkingDone, setThinkingDone] = useState(showResults);
  // workflowStep: 0="Running workflow...", 1="Thinking..." (non-picker only)
  const [workflowStep, setWorkflowStep] = useState(showResults ? 2 : 0);
  const [slowThinkingMsg, setSlowThinkingMsg] = useState(false);
  const isSlowAccount = accountName === "Lloyds Bank - Operations GBP";
  useEffect(() => {
    if (showResults) return;
    const slow = accountName === "Lloyds Bank - Operations GBP";
    const pickerFlow = accountName === "__picker__";
    if (!pickerFlow) {
      // 3-step sequence for specific account flow
      const thinkDuration = slow ? 20000 : 2400;
      const t1 = setTimeout(() => setWorkflowStep(1), 1200);
      const t2 = setTimeout(() => { setWorkflowStep(2); setThinkingDone(true); }, thinkDuration);
      const t3 = slow ? setTimeout(() => setSlowThinkingMsg(true), 5000) : null;
      return () => { clearTimeout(t1); clearTimeout(t2); if (t3) clearTimeout(t3); };
    } else {
      const t = setTimeout(() => setThinkingDone(true), 3000);
      return () => clearTimeout(t);
    }
  }, []);

  // Visual completion tracker — fires after thinkingDone + time for lines to type out
  const [line2VisualDone, setLine2VisualDone] = useState(showResults);
  useEffect(() => {
    if (!thinkingDone || showResults) return;
    // line1 ~38 chars + line2 ~48 chars at 18ms each ≈ 1550ms, add buffer
    const t = setTimeout(() => setLine2VisualDone(true), 900);
    return () => clearTimeout(t);
  }, [thinkingDone]);

  // Two-line message — line 2 starts after line 1 finishes, user bubble after line 2
  const line1Segments = [
    { text: "Great, let's reconcile a ", bold: false },
    { text: "bank account.",             bold: true  },
  ];
  const line1Full = line1Segments.map(s => s.text).join("");
  const { done: line1Done } = useTypewriter(line1Full, 18, showResults);

  const line2Text = "Tell me what bank account you want to reconcile";
  // line2 only types in picker flow; in row flow we skip it
  const { done: line2Done } = useTypewriter(isPicker && line1Done ? line2Text : "", 18, showResults);

  // Line 3 AI message — in picker flow: starts after user picks account; in row flow: starts after line1 finishes
  const isNoFeedAccount = effectiveAccountName === "American Express OP GBP";
  const clientUpload = showResults && existingStatement?.uploadedBy;
  const line3Segments = isNoFeedAccount ? [
    { text: selectedAccount, bold: true },
    { text: " doesn't have a bank feed connected. To reconcile this account, you'll need to provide a bank statement.", bold: false },
  ] : clientUpload ? [
    { text: "Client ", bold: false },
    { text: existingStatement.uploadedBy, bold: true },
    { text: ` uploaded a bank statement for `, bold: false },
    { text: selectedAccount, bold: true },
    { text: ` on ${existingStatement.date}${existingStatement.time ? " at " + existingStatement.time : ""}.`, bold: false },
  ] : [
    { text: "I couldn't find any bank statement for ", bold: false },
    { text: selectedAccount,                          bold: true  },
    { text: ". Could you upload the bank statement for me, or click All documents and select one that has already been uploaded.", bold: false },
  ];
  const line3Full = line3Segments.map(s => s.text).join("");
  const line3Trigger = isPicker ? accountSelected : (line1Done && accountSelected);
  const [line3ThinkingDone, setLine3ThinkingDone] = useState(showResults);
  const [thinkingSeconds, setThinkingSeconds] = useState(0);
  useEffect(() => {
    if (!line3Trigger || showResults) return;
    const slow = accountName === "Lloyds Bank - Operations GBP";
    setLine3ThinkingDone(false);
    setSlowThinkingMsg(false);
    setThinkingSeconds(0);
    const t = setTimeout(() => setLine3ThinkingDone(true), slow ? 20000 : 3000);
    const t2 = slow ? setTimeout(() => setSlowThinkingMsg(true), 5000) : null;
    const ticker = slow ? setInterval(() => setThinkingSeconds(s => s + 1), 1000) : null;
    return () => { clearTimeout(t); if (t2) clearTimeout(t2); if (ticker) clearInterval(ticker); };
  }, [line3Trigger]);
  const { done: line3Done } = useTypewriter(line3ThinkingDone ? line3Full : "", 18, showResults);

  // Line 3b — period selection question (AmEx only, after line3 finishes)
  const line3bText = "The statement period does not match with the financial close. Which period would you like to reconcile?";
  const { done: line3bDone } = useTypewriter(isNoFeedAccount && line3Done ? line3bText : "", 18, showResults);

  // Line 3c — AI confirmation after period is chosen
  const periodOptions = [
    { key: "full",        label: "Full accounting period",  sub: "Apr 1 – Apr 30" },
    { key: "overlapping", label: "Overlapping period",       sub: "Apr 5 – Apr 30" },
    { key: "statement",   label: "Statement period",         sub: "Apr 5 – May 5"  },
  ];
  const line3cText = periodChosen ? `Got it. Please upload the bank statement for the ${periodChosen.label.toLowerCase()} (${periodChosen.sub}).` : "";
  const { done: line3cDone } = useTypewriter(line3cText, 18, showResults);

  // Convert-path AI response (after user picks "Convert my bank statement to CSV and download")
  const convertRespText = "Upload your PDF or image statement and I'll convert it to CSV for you before running the reconciliation.";
  const { done: convertRespDone } = useTypewriter(feedProceedChoice === "convert" ? convertRespText : "", 18, showResults);

  // Line 4 — after file prep completes
  const fileCount = uploadedFiles ? uploadedFiles.length : 1;
  const line4Segments = fileCount > 1 ? [
    { text: "I have everything I need to reconcile ", bold: false },
    { text: selectedAccount,                          bold: true  },
    { text: " with account number ",                  bold: false },
    { text: "601613 31926819",                         bold: true  },
    { text: `. I've received `,                       bold: false },
    { text: `${fileCount} bank statements`,           bold: true  },
    { text: " and will reconcile across all of them.", bold: false },
  ] : [
    { text: "I have everything I need to reconcile ", bold: false },
    { text: selectedAccount,                          bold: true  },
    { text: " with account number ",                  bold: false },
    { text: "601613 31926819",                         bold: true  },
    { text: ".",                                      bold: false },
  ];
  const line4Full = line4Segments.map(s => s.text).join("");
  // Line 4a — AmEx only: brief message after upload, before card picker
  const line4aText = "I've processed the bank statement. I can see it contains transactions for multiple credit cards.";
  const { done: line4aDone } = useTypewriter(isNoFeedAccount && prepDone ? line4aText : "", 18, showResults);

  const { done: line4Done } = useTypewriter(prepDone && (!isNoFeedAccount || cardChosen) ? line4Full : "", 18, showResults);

  // Line 5 — after line 4
  const line5Text = "Tell me whenever you're ready to start.";
  const { done: line5Done } = useTypewriter(line4Done ? line5Text : "", 18, showResults);

  // Reconciliation summary data per account
  const RECON_SUMMARIES = {
    "Lloyds Bank - Business":       { openingBalance: 34210.00, closingBalance: 41890.75, transactions: 83 },
    "Lloyds Bank - Operations GBP": { openingBalance: 89350.00, closingBalance: 94120.40, transactions: 118 },
    "HSBC - Business Transactions": { openingBalance: 22780.50, closingBalance: 19450.25, transactions: 64 },
    "Barclays - Operations":        { openingBalance: 67100.00, closingBalance: 71580.90, transactions: 29 },
    "American Express OP GBP":      { openingBalance: 12450.00, closingBalance: 18230.50, transactions: 47 },
    "Mastercard Business":          { openingBalance: 8920.75,  closingBalance: 11340.00, transactions: 38 },
  };
  const reconSummary = RECON_SUMMARIES[effectiveAccountName] || { openingBalance: 10000, closingBalance: 12000, transactions: 40 };
  const reconMovement = reconSummary.closingBalance - reconSummary.openingBalance;
  const fmtGBP = (n) => (n < 0 ? "-£" : "£") + Math.abs(n).toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const reconDateRange = isNoFeedAccount && periodChosen ? periodChosen.sub : "Apr 1 – Apr 30, 2026";
  const [reconFrom, reconTo] = reconDateRange.includes("–") ? reconDateRange.split("–").map(s => s.trim()) : [reconDateRange, reconDateRange];

  // Line 5b — reconciliation summary (shown after line5, gates the "proceed?" card)
  const line5bIntroText = `For the bank account ${effectiveAccountName} we will reconcile:`;
  const { done: line5bDone } = useTypewriter(line5Done && !clientUpload ? line5bIntroText : "", 18, showResults);

  // Change flow — restart after "No, change the reconciliation"
  const changeAIText = "Which period would you like to reconcile?";
  const { done: changeAIDone } = useTypewriter(changeFlow ? changeAIText : "", 18);

  // Replace statement AI response — types when replace mode is active
  const replaceRespText = "Sure! Upload a new bank statement and I'll re-run the reconciliation against it.";
  const { chars: replaceRespChars, done: replaceRespDone } = useTypewriter(replaceStatementMode ? replaceRespText : "", 18);

  // Arrow key + Enter navigation for "Do you wish to proceed?" card
  const startOptions = [
    { label: "Yes, continue with suggested reconciliation", primary: true },
    { label: "No, change the reconciliation", primary: false },
  ];
  useEffect(() => {
    if (!line5bDone || startClicked) return;
    const handler = (e) => {
      if (e.key === "ArrowDown") { e.preventDefault(); setHighlightedStart(i => Math.min(i + 1, startOptions.length - 1)); }
      else if (e.key === "ArrowUp") { e.preventDefault(); setHighlightedStart(i => Math.max(i - 1, 0)); }
      else if (e.key === "Enter") {
        e.preventDefault();
        if (highlightedStart === 0) { setStartClicked(true); }
        else { setChangeFlow(true); setPeriodChosen(null); setCardChosen(null); setHighlightedCard(0); setHighlightedPeriod(0); setUploadedFiles(null); setPrepDone(false); setStartClicked(false); }
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [line5bDone, startClicked, highlightedStart]);

  // Arrow key + Enter navigation for period picker
  useEffect(() => {
    if (!isNoFeedAccount || !line3bDone || periodChosen) return;
    const handler = (e) => {
      if (e.key === "ArrowDown") { e.preventDefault(); setHighlightedPeriod(i => Math.min(i + 1, periodOptions.length - 1)); }
      else if (e.key === "ArrowUp") { e.preventDefault(); setHighlightedPeriod(i => Math.max(i - 1, 0)); }
      else if (e.key === "Enter") { e.preventDefault(); setPeriodChosen(periodOptions[highlightedPeriod]); }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [isNoFeedAccount, line3bDone, periodChosen, highlightedPeriod]);

  // Arrow key + Enter navigation for card picker
  useEffect(() => {
    if (!isNoFeedAccount || !line4aDone || cardChosen) return;
    const handler = (e) => {
      if (e.key === "ArrowDown") { e.preventDefault(); setHighlightedCard(i => Math.min(i + 1, cardOptions.length - 1)); }
      else if (e.key === "ArrowUp") { e.preventDefault(); setHighlightedCard(i => Math.max(i - 1, 0)); }
      else if (e.key === "Enter") { e.preventDefault(); setCardChosen(cardOptions[highlightedCard]); }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [isNoFeedAccount, line4aDone, cardChosen, highlightedCard]);

  // Close dropdown on click outside
  useEffect(() => {
    if (!dropdownOpen) return;
    const handler = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [dropdownOpen]);

  // Auto-scroll chat to bottom whenever new content appears
  useEffect(() => {
    // Small delay so step reveal animations finish before we measure height
    const t = setTimeout(() => {
      if (chatScrollRef.current) {
        chatScrollRef.current.scrollTo({ top: chatScrollRef.current.scrollHeight, behavior: "smooth" });
      }
    }, 120);
    return () => clearTimeout(t);
  }, [line1Done, line2Done, line3Done, line3bDone, line3cDone, line4aDone, line4Done, line5Done, line5bDone, prepDone, startClicked, stepStatuses, userMessages, accountSelected, replaceStatementMode, replaceRespDone, visibleSteps, periodChosen, cardChosen, changeFlow, changeAIDone]);

  // Track whether the chat is scrolled to the bottom
  useEffect(() => {
    const el = chatScrollRef.current;
    if (!el) return;
    const onScroll = () => {
      setIsAtBottom(el.scrollHeight - el.scrollTop - el.clientHeight < 40);
    };
    el.addEventListener("scroll", onScroll);
    return () => el.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100vh", fontFamily: "'Inter', sans-serif", background: "#FBFBFB", transform: isClosing ? "translateX(100%)" : undefined, transition: isClosing ? "transform 0.5s cubic-bezier(0.16,1,0.3,1)" : undefined }}>
      <style>{`
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }
        @keyframes pulse { 0%,80%,100%{opacity:0.3;transform:scale(0.9)} 40%{opacity:1;transform:scale(1)} }
        @keyframes spin { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes fadeIn { from{opacity:0;transform:translateY(4px)} to{opacity:1;transform:translateY(0)} }
        @keyframes resultsFadeIn { from{opacity:0} to{opacity:1} }
        @keyframes toastIn { from{opacity:0;transform:translateX(-50%) translateY(-12px)} to{opacity:1;transform:translateX(-50%) translateY(0)} }
        @keyframes textShimmer { 0%{background-position:200% center} 100%{background-position:-200% center} }
        @keyframes slideInFromRight { from{transform:translateX(100%)} to{transform:translateX(0)} }
        @keyframes slideUpFade { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
        @keyframes thinkingShimmer { 0%{background-position:200% center} 100%{background-position:-200% center} }
        @keyframes stepPop { 0%{transform:scale(0.8);opacity:0} 100%{transform:scale(1);opacity:1} }
        @keyframes stepReveal { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
        .mimo-loader { width:auto; height:20px; overflow:visible; }
        .mimo-loader path { fill:#1F2024; transform-box:fill-box; transform-origin:center; }
        .mimo-loader--spinning .m-right, .mimo-loader--spinning .m-left { animation:mimo-counter-a 2.2s infinite; }
        .mimo-loader--spinning .m-diag { animation:mimo-counter-b 2.2s infinite; }
        @keyframes mimo-counter-a {
          0%   { transform:rotate(0deg);    animation-timing-function:linear; }
          10%  { transform:rotate(0deg);    animation-timing-function:cubic-bezier(.65,0,.35,1); }
          45%  { transform:rotate(360deg);  animation-timing-function:linear; }
          55%  { transform:rotate(360deg);  animation-timing-function:cubic-bezier(.65,0,.35,1); }
          90%, 100% { transform:rotate(0deg); }
        }
        @keyframes mimo-counter-b {
          0%   { transform:rotate(0deg);    animation-timing-function:linear; }
          10%  { transform:rotate(0deg);    animation-timing-function:cubic-bezier(.65,0,.35,1); }
          45%  { transform:rotate(-360deg); animation-timing-function:linear; }
          55%  { transform:rotate(-360deg); animation-timing-function:cubic-bezier(.65,0,.35,1); }
          90%, 100% { transform:rotate(0deg); }
        }
      `}</style>

      {/* Top bar */}
      <div style={{ height: 96, background: "#FFFFFF", borderBottom: "1px solid #ECECEC", display: "flex", alignItems: "center", padding: "0 24px", flexShrink: 0, gap: 16, zIndex: 10, position: "relative" }}>
        <span style={{ fontSize: 24, fontWeight: 500, color: "#080908", flexShrink: 0, letterSpacing: "-1px" }}>Bank reconciliation</span>

        {/* Account dropdown */}
        <div ref={dropdownRef} style={{ position: "relative" }}>
          <button
            onClick={() => setDropdownOpen(o => !o)}
            style={{ display: "flex", alignItems: "center", gap: 8, padding: "0 12px", height: 40, border: "1px solid #E9E9EB", borderRadius: 8, background: "#FFFFFF", cursor: "pointer", fontSize: 14, fontWeight: 500, color: "#080908" }}
          >
            <span style={{ color: selectedAccount ? "#080908" : "#9D9D9E" }}>
              {selectedAccount || "Select account"}
            </span>
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ transition: "transform 0.2s ease", transform: dropdownOpen ? "rotate(180deg)" : "rotate(0deg)", flexShrink: 0 }}>
              <path d="M4 6L8 10L12 6" stroke="#080908" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </button>
          {dropdownOpen && (
            <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, background: "#FFFFFF", border: "1px solid #E9E9EB", borderRadius: 12, boxShadow: "0 8px 24px rgba(0,0,0,0.08)", zIndex: 100, minWidth: 380, overflow: "hidden", padding: "6px" }}>
              {accounts.map(acc => {
                const isSelected = acc === selectedAccount;
                const status = reconciledStatuses[acc];
                const count  = reconciledCounts[acc];
                const cfg    = STATUS_CONFIG[status];
                const label  = status === "suggestions" && count != null ? `${count} suggestions` : cfg?.label;
                return (
                  <button key={acc} onClick={() => { setSelectedAccount(acc); setDropdownOpen(false); }}
                    style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12, textAlign: "left", padding: "10px 12px", fontSize: 14, color: "#080908", fontWeight: isSelected ? 500 : 400, background: isSelected ? "#F5F5F5" : "transparent", border: "none", cursor: "pointer", borderRadius: 8, boxSizing: "border-box" }}
                    onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = "#FAFAFA"; }}
                    onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = "transparent"; }}
                  >
                    <span style={{ whiteSpace: "nowrap" }}>{acc}</span>
                    {cfg && (
                      <span style={{ fontSize: 12, fontWeight: 500, color: cfg.color, background: cfg.color + "18", padding: "2px 8px", borderRadius: 20, whiteSpace: "nowrap", flexShrink: 0 }}>
                        {label}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Audit log button — next to account dropdown */}
        {resultsVisible && canvasReady && (
          <button
            onClick={() => setAuditLogOpen(true)}
            style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "0 14px", height: 40, border: "1px solid #E9E9EB", borderRadius: 8, background: "#FFFFFF", cursor: "pointer", fontSize: 14, fontWeight: 500, color: "#080908", fontFamily: "'Inter', sans-serif", whiteSpace: "nowrap" }}
            onMouseEnter={e => { e.currentTarget.style.background = "#F5F5F5"; e.currentTarget.style.borderColor = "#CFCFD1"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "#FFFFFF"; e.currentTarget.style.borderColor = "#E9E9EB"; }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none"><path d="M21 12L9 12M21 6L9 6M21 18L9 18M5 12C5 12.5523 4.55228 13 4 13C3.44772 13 3 12.5523 3 12C3 11.4477 3.44772 11 4 11C4.55228 11 5 11.4477 5 12ZM5 6C5 6.55228 4.55228 7 4 7C3.44772 7 3 6.55228 3 6C3 5.44772 3.44772 5 4 5C4.55228 5 5 5.44772 5 6ZM5 18C5 18.5523 4.55228 19 4 19C3.44772 19 3 18.5523 3 18C3 17.4477 3.44772 17 4 17C4.55228 17 5 17.4477 5 18Z" stroke="#1F2024" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round"/></svg>
            Audit log
          </button>
        )}

        <div style={{ flex: 1 }} />

        {/* Uploaded file pills — all in one container with dividers */}
        {uploadedFiles && uploadedFiles.length > 0 && (
          <>
            <div style={{ display: "flex", alignItems: "center", height: 40, border: "1px solid #E9E9EB", borderRadius: 8, background: "#FFFFFF", flexShrink: 0, overflow: "hidden" }}>
              {uploadedFiles.map((file, i) => (
                <React.Fragment key={i}>
                  {i > 0 && <div style={{ width: 1, height: 32, background: "#E9E9EB", flexShrink: 0 }} />}
                  <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "0 12px" }}>
                    <FileIcon file={file} width={24} height={24} />
                    <span style={{ fontSize: 14, color: "#080908", fontWeight: 500, whiteSpace: "nowrap" }}>
                      {file.name}
                    </span>
                  </div>
                </React.Fragment>
              ))}
            </div>
            {resultsVisible && canvasReady && !effectiveIsCleanReconcile && (
              <div style={{ width: 1, height: 32, background: "#E9E9EB", flexShrink: 0, margin: "0 8px" }} />
            )}
          </>
        )}

        {/* Mark as complete button — shown when results canvas is open */}
        {resultsVisible && canvasReady && (() => {
          const allDoneNow = (resolvedCards.size + ignoredCards.size) >= totalSuggestions;
          return allDoneNow ? (
            <div style={{ display: "inline-flex", alignItems: "center", gap: 8, height: 40, padding: "0 16px", background: "#EEF2FF", borderRadius: 8, fontSize: 14, fontWeight: 500, color: "#4C71DF", fontFamily: "'Inter', sans-serif", flexShrink: 0 }}>
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                <circle cx="8" cy="8" r="8" fill="#4C71DF"/>
                <path d="M4.5 8.5L6.5 10.5L11.5 5.5" stroke="#FFFFFF" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              Completed
            </div>
          ) : (
            <Tooltip text="All suggestions will be marked as resolved. No entries will be changed in GL" placement="bottom">
              <PrimaryButton
                onClick={() => setMarkCompleteDrawerOpen(true)}
                style={{ height: 40, padding: "0 16px", fontSize: 14 }}
              >
                Mark as complete
              </PrimaryButton>
            </Tooltip>
          );
        })()}

        {resultsVisible && canvasReady && !effectiveIsCleanReconcile && (() => {
          const isHSBCCanvas = effectiveAccountName === "HSBC - Business Transactions";
          const totalSugg = ACCOUNT_TOTAL_SUGGESTIONS[effectiveAccountName] ?? 8;
          const resolved = resolvedCards.size + ignoredCards.size;
          const pct = totalSugg > 0 ? Math.min(100, Math.round((resolved / totalSugg) * 100)) : 0;
          const allDone = resolved >= totalSugg;
          return (
            <button
              onClick={() => setBoxesOpen(o => !o)}
              style={{
                display: "flex", alignItems: "center", gap: 0,
                marginRight: 8, cursor: "pointer", fontFamily: "inherit",
                border: "1px solid #E9E9EB",
                borderRadius: 8,
                background: "#FFFFFF",
                height: 40,
                minWidth: 40,
                padding: boxesOpen ? 0 : "0 12px 0 0",
                overflow: "hidden",
                justifyContent: "center",
                flexShrink: 0,
                transition: "padding 0.35s cubic-bezier(0.16,1,0.3,1), background 0.15s",
              }}
              onMouseEnter={e => e.currentTarget.style.background = "#F7F7F7"}
              onMouseLeave={e => e.currentTarget.style.background = "#FFFFFF"}
            >
              {/* Expandable text + progress — slides in/out */}
              <div style={{
                maxWidth: boxesOpen ? 0 : 180,
                opacity: boxesOpen ? 0 : 1,
                overflow: "hidden",
                transition: "max-width 0.35s cubic-bezier(0.16,1,0.3,1), opacity 0.2s, padding 0.35s cubic-bezier(0.16,1,0.3,1)",
                display: "flex", flexDirection: "column", gap: 4,
                paddingLeft: boxesOpen ? 0 : 12, paddingRight: boxesOpen ? 0 : 10,
              }}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
                  <span style={{ fontSize: 14, fontWeight: 500, color: "#545453", whiteSpace: "nowrap" }}>Suggestions</span>
                  <span style={{ fontSize: 14, fontWeight: 600, color: "#080908", whiteSpace: "nowrap" }}>{resolved}/{totalSugg}</span>
                </div>
                <div style={{ height: 2, background: "#E9E9EB", borderRadius: 1, overflow: "hidden" }}>
                  <div style={{ height: "100%", width: `${pct}%`, background: allDone ? "#4C71DF" : "#05A105", borderRadius: 1, transition: "width 0.4s ease, background 0.3s ease" }} />
                </div>
              </div>
              {/* Icon — always in the same spot */}
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" style={{ flexShrink: 0 }}>
                <path d="M15 21L15 3M16.2 21H7.8C6.11984 21 5.27976 21 4.63803 20.673C4.07354 20.3854 3.6146 19.9265 3.32698 19.362C3 18.7202 3 17.8802 3 16.2V7.8C3 6.11984 3 5.27976 3.32698 4.63803C3.6146 4.07354 4.07354 3.6146 4.63803 3.32698C5.27976 3 6.11984 3 7.8 3H16.2C17.8802 3 18.7202 3 19.362 3.32698C19.9265 3.6146 20.3854 4.07354 20.673 4.63803C21 5.27976 21 6.11984 21 7.8V16.2C21 17.8802 21 18.7202 20.673 19.362C20.3854 19.9265 19.9265 20.3854 19.362 20.673C18.7202 21 17.8802 21 16.2 21Z" stroke="#1F2024" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            </button>
          );
        })()}
        <button onClick={() => { const remaining = Math.max(0, totalSuggestions - resolvedCards.size - ignoredCards.size); onClose(canvasReady, (resolvedCards.size + ignoredCards.size) >= totalSuggestions, effectiveAccountName, remaining, resolvedCards, ignoredCards); }}
          style={{ border: "none", background: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", width: 30, height: 30, borderRadius: "50%", flexShrink: 0, padding: 0 }}
        >
          <svg width="30" height="30" viewBox="0 0 30 30" fill="none">
            <rect width="30" height="30" rx="15" fill="#F5F5F5"/>
            <path d="M20 10L10 20M10 10L20 20" stroke="#2A2A2A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </button>
      </div>

      {/* Audit log sidebar */}
      {auditLogOpen && <AuditTrailSidebar onClose={() => setAuditLogOpen(false)} accountName={effectiveAccountName} period={selectedPeriod} liveEntries={auditEntries} />}

      {/* Mark as complete drawer */}
      {markCompleteDrawerOpen && (() => {
        const unreviewed = Math.max(0, totalSuggestions - resolvedCards.size - ignoredCards.size);
        const markAll = () => {
          setResolvedCards(new Set(Array.from({ length: totalSuggestions }, (_, i) => i)));
          addAuditEntry("Mark as complete", `All ${totalSuggestions} suggestions marked as resolved.${markCompleteComment.trim() ? ` Note: ${markCompleteComment.trim()}` : ""}`, "#4C71DF");
          if (markCompleteComment.trim()) {
            onAddComment?.(effectiveAccountName, markCompleteComment.trim());
          }
          setMarkCompleteDrawerOpen(false);
          setMarkCompleteComment("");
        };
        return (
          <>
            <div onClick={() => setMarkCompleteDrawerOpen(false)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.15)", zIndex: 200 }} />
            <div style={{ position: "fixed", top: 0, right: 0, bottom: 0, width: 600, background: "#FFFFFF", zIndex: 201, display: "flex", flexDirection: "column", animation: "slideInFromRight 0.25s ease both" }}>
              <div style={{ height: 112, padding: "0 24px", flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: "1px solid #ECECEC", boxSizing: "border-box" }}>
                <h2 style={{ fontSize: 24, fontWeight: 500, color: "#080908", margin: 0, letterSpacing: "-0.3px" }}>Review suggestions before reconciling</h2>
                <button onClick={() => setMarkCompleteDrawerOpen(false)} style={{ border: "none", background: "none", cursor: "pointer", padding: 0 }}>
                  <svg width="30" height="30" viewBox="0 0 30 30" fill="none"><rect width="30" height="30" rx="15" fill="#F5F5F5"/><path d="M20 10L10 20M10 10L20 20" stroke="#2A2A2A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                </button>
              </div>
              <div style={{ flex: 1, padding: "20px 24px", overflowY: "auto" }}>
                <p style={{ fontSize: 14, color: "#000", lineHeight: "22px", margin: "0 0 24px" }}>
                  This account has <strong style={{ color: "#000" }}>{unreviewed} unreviewed {unreviewed === 1 ? "suggestion" : "suggestions"}</strong>. You can go back and review them, or mark all suggestions as resolved with a comment explaining why.
                </p>
                <label style={{ display: "block", fontSize: 14, color: "#000", marginBottom: 4 }}>Comment</label>
                <textarea
                  value={markCompleteComment}
                  onChange={e => setMarkCompleteComment(e.target.value)}
                  placeholder="Explain why this account is being marked as complete without taking action on all suggestions."
                  style={{ width: "100%", minHeight: 120, padding: "8px 10px", border: "1px solid #E9E9EB", borderRadius: 6, fontSize: 14, fontFamily: "'Inter', sans-serif", color: "#080908", lineHeight: "22px", resize: "vertical", outline: "none", boxSizing: "border-box", background: "#FFFFFF" }}
                  onFocus={e => e.currentTarget.style.borderColor = "#CFCFD1"}
                  onBlur={e => e.currentTarget.style.borderColor = "#E9E9EB"}
                />
              </div>
              <div style={{ padding: "16px 24px", borderTop: "1px solid #E9E9EB", display: "flex", alignItems: "center", gap: 12, flexShrink: 0 }}>
                <button onClick={() => setMarkCompleteDrawerOpen(false)}
                  style={{ flex: 1, height: 40, borderRadius: 6, border: "1px solid #E9E9EB", background: "#FFFFFF", fontSize: 14, fontWeight: 500, color: "#080908", cursor: "pointer", fontFamily: "'Inter', sans-serif" }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = "#CFCFD1"; e.currentTarget.style.background = "#FAFAFA"; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = "#E9E9EB"; e.currentTarget.style.background = "#FFFFFF"; }}>
                  Back to reconciliation
                </button>
                <button onClick={markAll}
                  style={{ flex: 1, height: 40, borderRadius: 6, border: "none", background: "#05A105", color: "#FFFFFF", fontSize: 14, fontWeight: 500, cursor: "pointer", fontFamily: "'Inter', sans-serif" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#058F05"}
                  onMouseLeave={e => e.currentTarget.style.background = "#05A105"}>
                  Mark as complete
                </button>
              </div>
            </div>
          </>
        );
      })()}

      {/* Content area — position:relative so the canvas overlay can anchor to it */}
      <div style={{ display: "flex", flex: 1, overflow: "hidden", position: "relative", padding: 16 }}>

      {/* Left: chat panel — in flex flow so canvas naturally opens beside it */}
      <div style={{
        display: "flex", flexDirection: "column",
        width: resultsVisible ? chatWidth : "100%",
        flexShrink: 0,
        transition: isDragging ? "none" : "width 0.72s cubic-bezier(0.16, 1, 0.3, 1)",
        overflow: "hidden",
        willChange: "width",
        position: "relative",
        zIndex: 1,
      }}>

        {/* Floating scroll-to-bottom button */}
        {resultsVisible && (
          <button
            onClick={() => {
              const el = chatScrollRef.current;
              if (el) el.scrollTo({ top: el.scrollHeight, behavior: "smooth" });
            }}
            style={{
              position: "absolute", bottom: 218, left: "50%", transform: "translateX(-50%)",
              zIndex: 10,
              width: 32, height: 32, borderRadius: "50%",
              background: "#FFFFFF", border: "none", cursor: "pointer",
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: "0 2px 12px rgba(0,0,0,0.12), 0 0 0 1px rgba(0,0,0,0.06)",
              opacity: isAtBottom ? 0 : 1,
              pointerEvents: isAtBottom ? "none" : "auto",
              transition: "opacity 0.35s ease",
            }}
            onMouseEnter={e => e.currentTarget.style.background = "#F5F5F5"}
            onMouseLeave={e => e.currentTarget.style.background = "#FFFFFF"}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
              <path d="M12 5V19M12 19L19 12M12 19L5 12" stroke="#1F2024" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </button>
        )}

      {/* Chat area */}
      <div style={{ flex: 1, overflow: "hidden", position: "relative", display: "flex", flexDirection: "column" }}>
      <div ref={chatScrollRef} style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", scrollBehavior: "smooth" }}>
        {/* Top fade — only in sidebar mode, inside scroll so it doesn't cover the scrollbar */}
        {resultsVisible && <div style={{ position: "sticky", top: 0, left: 0, right: 0, height: 40, marginBottom: -40, background: "linear-gradient(to bottom, rgba(251,251,251,1) 0%, rgba(251,251,251,0) 100%)", zIndex: 2, pointerEvents: "none", flexShrink: 0 }} />}
        <div style={{ maxWidth: 680, width: "100%", margin: "0 auto", padding: resultsVisible ? "24px 24px 72px" : "24px 24px 72px", flex: 1, display: "flex", flexDirection: "column" }}>

          {!clientUpload && (
            <>
              <WorkflowCard />
              {thinkingDone && (
                <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", width: resultsVisible ? "90%" : "70%" }}>
                  {isPicker && <p style={{ marginTop: 0 }}><StreamingMessage segments={line1Segments} speed={18} instant={showResults} /></p>}
                  {isPicker && line1Done && (
                    <p style={{ marginTop: 6 }}>
                      <StreamingMessage key="line2" segments={[{ text: line2Text, bold: false }]} speed={18} instant={showResults} />
                    </p>
                  )}
                </div>
              )}
              {/* Logo row — only visible while on the initial greeting, hidden once user has acted */}
              {!thinkingDone && !accountSelected && <div style={{ display: "flex", alignItems: "center", gap: 16, marginTop: 12, animation: "slideUpFade 0.5s cubic-bezier(0.16,1,0.3,1) both" }}>
                <svg className="mimo-loader mimo-loader--spinning" viewBox="0 0 22 20" xmlns="http://www.w3.org/2000/svg" aria-label="Thinking">
                  <path className="m-right" d="M21.2948 0.314453H16.2686V19.8217H21.2948V0.314453Z"/>
                  <path className="m-diag"  d="M3.55406 0L0 3.55406L10.9144 14.4685L14.4685 10.9144L3.55406 0Z"/>
                  <path className="m-left"  d="M5.56185 10.7432H0.535645V19.8207H5.56185V10.7432Z"/>
                </svg>
                <span style={{
                  fontSize: 14, display: "inline-block",
                  background: "linear-gradient(90deg, #8C8C8B 0%, #8C8C8B 25%, #D4D4D4 50%, #8C8C8B 75%, #8C8C8B 100%)",
                  backgroundSize: "200% auto",
                  WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                  backgroundClip: "text",
                  animation: "thinkingShimmer 2.4s linear infinite, slideUpFade 0.4s cubic-bezier(0.16,1,0.3,1) 0.15s both",
                }}>{!isPicker && workflowStep === 0 ? "Running workflow..." : "Thinking..."}</span>
              </div>}
              {slowThinkingMsg && !thinkingDone && !accountSelected && (
                <div style={{ marginTop: 8, paddingLeft: 4, animation: "slideUpFade 0.5s cubic-bezier(0.16,1,0.3,1) both" }}>
                  <span style={{
                    fontSize: 13, display: "inline-block",
                    background: "linear-gradient(90deg, #BCBCBC 0%, #BCBCBC 20%, #6E6E6E 50%, #BCBCBC 80%, #BCBCBC 100%)",
                    backgroundSize: "200% auto",
                    WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                    backgroundClip: "text",
                    animation: "thinkingShimmer 2.8s linear infinite",
                  }}>This is taking a bit longer — working on matching transactions against your GL records in Xero...</span>
                </div>
              )}
            </>
          )}

          {/* User reply bubble — appears after account is selected and line1 is done */}
          {!clientUpload && accountSelected && line1Done && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20, animation: "slideUpFade 0.4s cubic-bezier(0.16,1,0.3,1) both" }}>
              <div style={{
                maxWidth: 400,
                background: "#F1F8F0",
                borderRadius: "12px 12px 2px 12px",
                padding: "10px 14px",
                fontSize: 14,
                color: "#080908",
                lineHeight: "22px",
              }}>
                {selectedAccount}
              </div>
            </div>
          )}

          {/* AI line 3 — thinking + couldn't find statement */}
          {line3Trigger && (
            <>
              {!line3ThinkingDone && (
                <>
                  <div style={{ display: "flex", alignItems: "center", gap: 16, marginTop: 20, animation: "slideUpFade 0.5s cubic-bezier(0.16,1,0.3,1) 0.5s both" }}>
                    <svg className="mimo-loader mimo-loader--spinning" viewBox="0 0 22 20" xmlns="http://www.w3.org/2000/svg" aria-label="Thinking">
                      <path className="m-right" d="M21.2948 0.314453H16.2686V19.8217H21.2948V0.314453Z"/>
                      <path className="m-diag"  d="M3.55406 0L0 3.55406L10.9144 14.4685L14.4685 10.9144L3.55406 0Z"/>
                      <path className="m-left"  d="M5.56185 10.7432H0.535645V19.8207H5.56185V10.7432Z"/>
                    </svg>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{
                        fontSize: 14, display: "inline-block",
                        background: "linear-gradient(90deg, #8C8C8B 0%, #8C8C8B 25%, #D4D4D4 50%, #8C8C8B 75%, #8C8C8B 100%)",
                        backgroundSize: "200% auto",
                        WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                        backgroundClip: "text",
                        animation: "thinkingShimmer 2.4s linear infinite",
                      }}>Thinking...</span>
                      {slowThinkingMsg && (
                        <>
                          <span style={{ fontSize: 14, color: "#7C7C7C" }}>·</span>
                          <span style={{ fontSize: 14, color: "#7C7C7C", fontVariantNumeric: "tabular-nums" }}>{thinkingSeconds}s</span>
                        </>
                      )}
                    </div>
                  </div>
                  {slowThinkingMsg && (
                    <div style={{ marginTop: 20, animation: "slideUpFade 0.5s cubic-bezier(0.16,1,0.3,1) both" }}>
                      <span style={{
                        fontSize: 14, display: "inline-block",
                        background: "linear-gradient(90deg, #7C7C7C 0%, #7C7C7C 20%, #C0C0C0 50%, #7C7C7C 80%, #7C7C7C 100%)",
                        backgroundSize: "200% auto",
                        WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                        backgroundClip: "text",
                        animation: "thinkingShimmer 2.8s linear infinite",
                      }}>This is taking a bit longer — working on matching transactions against your GL records in Xero...</span>
                    </div>
                  )}
                </>
              )}
              {line3ThinkingDone && (
                <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
                  <p><StreamingMessage key="line3" segments={line3Segments} speed={18} instant={showResults} /></p>
                </div>
              )}
            </>
          )}

          {/* Change flow — user bubble + new period question */}
          {changeFlow && (
            <>
              <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20, animation: "slideUpFade 0.4s cubic-bezier(0.16,1,0.3,1) both" }}>
                <div style={{ maxWidth: 400, background: "#F1F8F0", borderRadius: "12px 12px 2px 12px", padding: "10px 14px", fontSize: 14, color: "#080908", lineHeight: "22px" }}>
                  No, change the reconciliation
                </div>
              </div>
              {changeAIDone !== undefined && (
                <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
                  <p style={{ margin: 0 }}><StreamingMessage key="changeAI" segments={[{ text: changeAIText, bold: false }]} speed={18} /></p>
                </div>
              )}
            </>
          )}

          {/* AI line 3b — period question (AmEx only) */}
          {isNoFeedAccount && line3Done && !changeFlow && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
              <p style={{ margin: 0 }}><StreamingMessage key="line3b" segments={[{ text: line3bText, bold: false }]} speed={18} instant={showResults} /></p>
            </div>
          )}

          {/* User bubble — period selection */}
          {isNoFeedAccount && periodChosen && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20, animation: "slideUpFade 0.4s cubic-bezier(0.16,1,0.3,1) both" }}>
              <div style={{
                maxWidth: 400,
                background: "#F1F8F0",
                borderRadius: "12px 12px 2px 12px",
                padding: "10px 14px",
                fontSize: 14,
                color: "#080908",
                lineHeight: "22px",
              }}>
                {periodChosen.label} · {periodChosen.sub}
              </div>
            </div>
          )}

          {/* AI line 3c — confirmation after period chosen */}
          {isNoFeedAccount && periodChosen && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
              <p style={{ margin: 0 }}><StreamingMessage key="line3c" segments={[{ text: line3cText, bold: false }]} speed={18} instant={showResults} /></p>
            </div>
          )}

          {/* User bubble — file preview after upload */}
          {uploadedFiles && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20 }}>
              <div style={{ display: "flex", flexDirection: "row", flexWrap: "wrap", gap: 10, justifyContent: "flex-end", maxWidth: "100%" }}>
                {uploadedFiles.map((file, idx) => (
                  <div key={idx} style={{
                    width: 180,
                    background: "#FFFFFF",
                    border: "1px solid #E9E9EB",
                    borderRadius: 8,
                    overflow: "hidden",
                  }}>
                    {previewUrl && idx === 0 ? (
                      <img src={previewUrl} alt="preview" style={{ width: "100%", display: "block" }} />
                    ) : (
                      /* Mock document body */
                      <div style={{ padding: "14px 12px 12px", background: "#FFFFFF", borderBottom: "1px solid #F0F0F0" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                          {[55, 30].map((w, i) => <div key={i} style={{ height: 5, borderRadius: 3, background: "#E8E8E8", width: `${w}%` }} />)}
                        </div>
                        {[100, 75, 90, 60, 85, 70, 95, 55, 80].map((w, i) => (
                          <div key={i} style={{ height: 4, borderRadius: 2, background: i % 3 === 2 ? "#F0F0F0" : "#EBEBEB", width: `${w}%`, marginBottom: 5 }} />
                        ))}
                        <div style={{ marginTop: 8, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 4 }}>
                          {[80, 60, 90, 70, 75, 55].map((w, i) => (
                            <div key={i} style={{ height: 4, borderRadius: 2, background: "#EBEBEB", width: `${w}%` }} />
                          ))}
                        </div>
                      </div>
                    )}
                    {/* Footer with icon + filename */}
                    <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 12px" }}>
                      <FileIcon file={file} width={18} height={22} />
                      <span style={{ fontSize: 14, fontWeight: 500, color: "#080908", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>{file.name}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* CSV conversion progress — convert path only */}
          {feedProceedChoice === "convert" && uploadedFiles && !csvConvertDone && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%", display: "flex", alignItems: "center", gap: 10 }}>
              {csvConverting ? (
                <>
                  <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0, animation: "spin 1s linear infinite" }}>
                    <circle cx="8" cy="8" r="6.5" stroke="#E9E9EB" strokeWidth="1.5"/>
                    <path d="M8 1.5A6.5 6.5 0 0 1 14.5 8" stroke="#05A105" strokeWidth="1.5" strokeLinecap="round"/>
                  </svg>
                  <span>Converting your statement to CSV…</span>
                </>
              ) : (
                <span style={{ color: "#8C8C8B" }}>Preparing…</span>
              )}
            </div>
          )}

          {/* CSV conversion done — steps card */}
          {feedProceedChoice === "convert" && csvConvertDone && (
            <>
              <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
                <p>Your statement has been converted to CSV and is ready to download. You'll need to upload it to Xero to complete the bank reconciliation.</p>
              </div>
              <div style={{ marginTop: 16, background: "#FFFFFF", border: "1px solid #E9E9EB", borderRadius: 8, padding: "24px 24px 16px", boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04)" }}>
                <p style={{ fontSize: 14, fontWeight: 500, color: "#080908", marginBottom: 16, marginTop: 0 }}>Proceed with bank statement</p>
                {/* Step 1 — Download CSV */}
                <div
                  onClick={() => {
                    const csv = "Date,Description,Amount\n2026-03-01,Opening balance,0.00\n2026-03-05,Yorkshire Tea Estates,-240.00\n2026-03-12,Clifton & Harrow Supplies,-1180.00\n2026-03-14,Meridian Office Solutions,-530.00";
                    const blob = new Blob([csv], { type: "text/csv" });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement("a");
                    a.href = url;
                    a.download = (uploadedFiles[0]?.name?.replace(/\.[^.]+$/, "") || "statement") + "-converted.csv";
                    a.click();
                    URL.revokeObjectURL(url);
                  }}
                  style={{ display: "flex", alignItems: "center", gap: 12, width: "100%", padding: "14px 18px", marginBottom: 8, background: "#F7F7F7", borderRadius: 10, cursor: "pointer", boxSizing: "border-box", transition: "background 0.1s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#F0F0F0"}
                  onMouseLeave={e => e.currentTarget.style.background = "#F7F7F7"}>
                  <span style={{ width: 22, height: 22, borderRadius: "50%", background: "#E9E9EB", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 12, fontWeight: 600, color: "#545453" }}>1</span>
                  <span style={{ fontSize: 14, color: "#080908" }}>Download file in CSV</span>
                </div>
                {/* Step 2 — Go to Xero */}
                <div
                  onClick={() => window.open("https://go.xero.com", "_blank", "noopener,noreferrer")}
                  style={{ display: "flex", alignItems: "center", gap: 12, width: "100%", padding: "14px 18px", marginBottom: 8, background: "#F7F7F7", borderRadius: 10, cursor: "pointer", boxSizing: "border-box", transition: "background 0.1s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#F0F0F0"}
                  onMouseLeave={e => e.currentTarget.style.background = "#F7F7F7"}>
                  <span style={{ width: 22, height: 22, borderRadius: "50%", background: "#E9E9EB", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 12, fontWeight: 600, color: "#545453" }}>2</span>
                  <span style={{ fontSize: 14, color: "#080908" }}>Go to Xero and import statement</span>
                </div>
                {/* Step 3 — Reconcile now */}
                <div
                  onClick={() => { setFeedProceedChoice("upload"); setCsvConvertDone(false); setPrepDone(true); setStartClicked(true); }}
                  style={{ display: "flex", alignItems: "center", gap: 12, width: "100%", padding: "14px 18px", marginBottom: 8, background: "#F7F7F7", borderRadius: 10, cursor: "pointer", boxSizing: "border-box", transition: "background 0.1s" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#F0F0F0"}
                  onMouseLeave={e => e.currentTarget.style.background = "#F7F7F7"}>
                  <span style={{ width: 22, height: 22, borderRadius: "50%", background: "#E9E9EB", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 12, fontWeight: 600, color: "#545453" }}>3</span>
                  <span style={{ fontSize: 14, color: "#080908" }}>I have imported the statement in Xero. Reconcile account now</span>
                </div>
              </div>
            </>
          )}

          {/* AI line 4a — AmEx: processed statement message before card picker */}
          {isNoFeedAccount && prepDone && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
              <p style={{ margin: 0 }}><StreamingMessage key="line4a" segments={[{ text: line4aText, bold: false }]} speed={18} instant={showResults} /></p>
            </div>
          )}

          {/* User bubble — card selection */}
          {isNoFeedAccount && cardChosen && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20, animation: "slideUpFade 0.4s cubic-bezier(0.16,1,0.3,1) both" }}>
              <div style={{ maxWidth: 400, background: "#F1F8F0", borderRadius: "12px 12px 2px 12px", padding: "10px 14px", fontSize: 14, color: "#080908", lineHeight: "22px" }}>
                {cardChosen.label}
              </div>
            </div>
          )}

          {/* AI line 4 — has everything needed (normal flow only) */}
          {prepDone && feedProceedChoice !== "convert" && (!isNoFeedAccount || cardChosen) && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
              <p><StreamingMessage key="line4" segments={line4Segments} speed={18} instant={showResults} /></p>
            </div>
          )}

          {/* AI line 5b — reconciliation summary before proceed card */}
          {line5Done && !clientUpload && (
            <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
              <p style={{ margin: "0 0 10px" }}>
                <StreamingMessage key="line5b" segments={[
                  { text: "For the bank account ", bold: false },
                  { text: effectiveAccountName, bold: true },
                  { text: " we will reconcile:", bold: false },
                ]} speed={18} instant={showResults} />
              </p>
              {line5bDone && (
                <ul style={{ margin: 0, padding: "0 0 0 18px", display: "flex", flexDirection: "column", gap: 4 }}>
                  <li>From <strong>{reconFrom}</strong> to <strong>{reconTo}</strong></li>
                  <li>Opening balance: <strong>{fmtGBP(reconSummary.openingBalance)}</strong></li>
                  <li>Closing balance: <strong>{fmtGBP(reconSummary.closingBalance)}</strong></li>
                  <li>Movement: <strong>{fmtGBP(reconMovement)}</strong></li>
                  <li>Transactions: <strong>{reconSummary.transactions} transactions</strong></li>
                </ul>
              )}
            </div>
          )}

          {/* User sent messages + re-upload flow */}
          {userMessages.map((msg, i) => (
            <div key={i}>
              <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
                <div style={{ maxWidth: 400, background: "#F1F8F0", borderRadius: "12px 12px 2px 12px", padding: "10px 14px", fontSize: 14, color: "#080908", lineHeight: "22px" }}>
                  {msg}
                </div>
              </div>
              {i === userMessages.length - 1 && (
                <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20 }}>
                  <p>Sure! Please upload the new bank statement.</p>
                </div>
              )}
            </div>
          ))}

          {/* User bubble — appears when "Start reconciliation" is clicked */}
          {startClicked && (
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
              <div style={{
                maxWidth: 400,
                background: clientUpload ? "#F0F0F0" : "#EAF2E2",
                borderRadius: "12px 12px 2px 12px",
                padding: "10px 14px",
                fontSize: 14,
                color: clientUpload ? "#8C8C8B" : "#080908",
                lineHeight: "22px",
                fontStyle: clientUpload ? "italic" : "normal",
              }}>
                {clientUpload ? "Reconciliation triggered automatically" : "Yes, continue with suggested reconciliation"}
              </div>
            </div>
          )}

          {/* Reconciliation progress */}
          {startClicked && visibleSteps > 0 && (
            <div style={{ marginTop: 24 }}>
              {/* Header */}
              <div
                onClick={() => setReconciliationCollapsed(c => !c)}
                style={{ display: "flex", alignItems: "flex-start", gap: 12, marginBottom: reconciliationCollapsed ? 0 : 20, cursor: "pointer" }}
              >
                <div style={{ width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                    <path d="M6.50065 6.4987L10.6257 10.6237M6.50065 6.4987H3.75065L2.83398 3.7487L3.75065 2.83203L6.50065 3.7487V6.4987ZM18.6547 3.51129L16.2461 5.91994C15.8831 6.28296 15.7016 6.46446 15.6335 6.67377C15.5737 6.85787 15.5737 7.05619 15.6335 7.2403C15.7016 7.4496 15.8831 7.63111 16.2461 7.99412L16.4636 8.21161C16.8266 8.57462 17.0081 8.75613 17.2174 8.82414C17.4015 8.88396 17.5998 8.88396 17.7839 8.82414C17.9932 8.75613 18.1747 8.57462 18.5377 8.21161L20.7908 5.95852C21.0335 6.54901 21.1673 7.19573 21.1673 7.8737C21.1673 10.6581 18.9101 12.9154 16.1257 12.9154C15.79 12.9154 15.4619 12.8826 15.1446 12.82C14.699 12.7321 14.4761 12.6881 14.3411 12.7016C14.1975 12.7159 14.1267 12.7374 13.9995 12.8055C13.8798 12.8696 13.7597 12.9896 13.5196 13.2298L6.95898 19.7904C6.19959 20.5497 4.96838 20.5497 4.20899 19.7904C3.44959 19.031 3.44959 17.7997 4.20899 17.0403L10.7696 10.4798C11.0097 10.2396 11.1298 10.1196 11.1938 9.99989C11.2619 9.87265 11.2834 9.80188 11.2977 9.65827C11.3112 9.5232 11.2673 9.30038 11.1794 8.85475C11.1168 8.53742 11.084 8.20939 11.084 7.8737C11.084 5.08926 13.3412 2.83203 16.1257 2.83203C17.0474 2.83203 17.9113 3.07937 18.6547 3.51129ZM12.0007 14.7486L17.0423 19.7903C17.8017 20.5497 19.0329 20.5497 19.7923 19.7903C20.5517 19.0309 20.5517 17.7996 19.7923 17.0403L15.6447 12.8927C15.3511 12.8649 15.0648 12.812 14.788 12.736C14.4314 12.6381 14.0402 12.7092 13.7787 12.9707L12.0007 14.7486Z" stroke="#8C8C8B" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <span style={{ fontSize: 15, fontWeight: 600, color: "#080908" }}>Reconciliation</span>
                    <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ transition: "transform 0.2s ease", transform: reconciliationCollapsed ? "rotate(180deg)" : "rotate(0deg)" }}>
                      <path d="M3 8.5L7 4.5L11 8.5" stroke="#8C8C8B" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  </div>
                  <span style={{ fontSize: 13, color: "#8C8C8B" }}>
                    {stepsPopulated && stepStatuses.every(s => s === "done") ? "Completed" : "In progress"}
                  </span>
                </div>
              </div>

              {/* Steps */}
              {!reconciliationCollapsed && RECONCILIATION_STEPS.map((step, i) => {
                if (i >= visibleSteps) return null;
                const status = stepsPopulated ? (stepStatuses[i] || "pending") : "pending";
                const isLast = i === RECONCILIATION_STEPS.length - 1;
                return (
                  <div key={i} ref={el => stepRowRefs.current[i] = el} style={{ display: "flex", gap: 16, animation: "stepReveal 0.4s cubic-bezier(0.16,1,0.3,1) both" }}>
                    {/* Circle + connector line */}
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", flexShrink: 0, paddingTop: 2, overflow: "visible" }}>
                      <div style={{ width: 20, height: 20, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", overflow: "visible" }}>
                        {status === "done" && (
                          <svg key={`done-${i}`} width="20" height="20" viewBox="0 0 20 20" fill="none" style={{ animation: "stepPop 0.35s cubic-bezier(0.34,1.4,0.64,1) both", overflow: "visible" }}>
                            <circle cx="10" cy="10" r="10" fill="#05A105"/>
                            <path d="M5.5 10.5L8.5 13.5L14.5 7" stroke="#FFFFFF" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round"/>
                          </svg>
                        )}
                        {status === "active" && (
                          <svg width="20" height="20" viewBox="0 0 20 20" fill="none" style={{ animation: "spin 0.75s linear infinite" }}>
                            <path d="M10 2A8 8 0 1 1 2 10" stroke="#05A105" strokeWidth="1.5" strokeLinecap="round"/>
                          </svg>
                        )}
                        {status === "pending" && (
                          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                            <circle cx="10" cy="10" r="9.25" stroke="#E9E9EB" strokeWidth="1.5"/>
                          </svg>
                        )}
                      </div>
                      {!isLast && i + 1 < visibleSteps && (
                        <div style={{ width: 1, flexGrow: 1, minHeight: 20, background: "#E9E9EB", margin: "4px 0" }} />
                      )}
                    </div>

                    {/* Content */}
                    <div style={{ paddingBottom: isLast ? 0 : 20, paddingTop: 0 }}>
                      <div style={{
                        fontSize: 14, lineHeight: "24px",
                        fontWeight: 400,
                        color: status === "pending" ? "#BCBCBC" : "#080908",
                        transition: "color 0.3s ease",
                      }}>
                        {step.title}
                      </div>
                      {(stepSubtexts[i] || status === "done") && step.subtext && (
                        <div style={{ fontSize: 13, color: "#8C8C8B", marginTop: 2, lineHeight: "18px", animation: "fadeIn 0.3s ease" }}>
                          {step.subtext}
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Replace statement flow — appears after reconciliation is complete */}
          {replaceStatementMode && (
            <>
              {/* User bubble */}
              <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 20 }}>
                <div style={{ maxWidth: 400, background: "#F1F8F0", borderRadius: "12px 12px 2px 12px", padding: "10px 14px", fontSize: 14, color: "#080908", lineHeight: "22px" }}>
                  New statement
                </div>
              </div>
              {/* AI response — typed out */}
              {replaceRespChars && (
                <div style={{ fontSize: 14, color: "#080908", lineHeight: "22px", marginTop: 20, width: "70%" }}>
                  <p style={{ margin: 0 }}>{replaceRespChars}</p>
                </div>
              )}
            </>
          )}

          {/* Mimo loader — shown inline while AI is preparing next response */}
          {(() => {
            const isStreaming = (isPicker && thinkingDone && !line2VisualDone)
              || thinkingDone && (!line1Done
              || (isPicker && line1Done && !line2Done))
              || (line3ThinkingDone && !line3Done && (isPicker ? (line2Done && accountSelected) : line1Done))
              || (isNoFeedAccount && line3Done && !line3bDone && !changeFlow)
              || (changeFlow && !changeAIDone)
              || (isNoFeedAccount && periodChosen && !line3cDone)
              || (uploadedFiles && !prepDone)
              || (isNoFeedAccount && prepDone && !line4aDone)
              || (prepDone && (!isNoFeedAccount || cardChosen) && !line4Done)
              || (line4Done && !line5Done)
              || (line5Done && !clientUpload && !line5bDone);
            return isStreaming ? (
              <div style={{ display: "flex", alignItems: "center", gap: 16, marginTop: 20 }}>
                <svg className="mimo-loader mimo-loader--spinning" viewBox="0 0 22 20" xmlns="http://www.w3.org/2000/svg" aria-label="Loading">
                  <path className="m-right" d="M21.2948 0.314453H16.2686V19.8217H21.2948V0.314453Z"/>
                  <path className="m-diag"  d="M3.55406 0L0 3.55406L10.9144 14.4685L14.4685 10.9144L3.55406 0Z"/>
                  <path className="m-left"  d="M5.56185 10.7432H0.535645V19.8207H5.56185V10.7432Z"/>
                </svg>
                <span style={{
                  fontSize: 14, display: "inline-block",
                  background: "linear-gradient(90deg, #8C8C8B 0%, #8C8C8B 25%, #D4D4D4 50%, #8C8C8B 75%, #8C8C8B 100%)",
                  backgroundSize: "200% auto",
                  WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                  backgroundClip: "text",
                  animation: "thinkingShimmer 2.4s linear infinite",
                }}>Writing...</span>
              </div>
            ) : null;
          })()}

          <div ref={chatEndRef} />
        </div>
      </div>

      {/* Account picker — pinned at the bottom */}
      {!clientUpload && isPicker && thinkingDone && line2Done && line2VisualDone && !accountSelected && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <AccountPicker
              accounts={accounts}
              highlightedAccount={highlightedAccount}
              setHighlightedAccount={setHighlightedAccount}
              onConfirm={(acc) => { setSelectedAccount(acc); setAccountSelected(true); }}
            />
          </div>
        </div>
      )}

      {/* Period picker — pinned at the bottom (AmEx only) */}
      {isNoFeedAccount && (changeFlow ? changeAIDone : line3bDone) && !periodChosen && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <div style={{
              background: "#FFFFFF",
              border: "1px solid #E9E9EB",
              borderRadius: 8,
              padding: "24px 24px 16px",
              width: "100%",
              boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04)",
            }}>
              <p style={{ fontSize: 14, fontWeight: 500, color: "#080908", marginBottom: 16, marginTop: 0 }}>Which period would you like to reconcile?</p>
              {periodOptions.map((opt, i) => {
                const isActive = i === highlightedPeriod;
                return (
                  <div
                    key={opt.key}
                    onClick={() => setPeriodChosen(opt)}
                    onMouseEnter={() => setHighlightedPeriod(i)}
                    style={{
                      display: "flex", alignItems: "center", justifyContent: "space-between",
                      width: "100%", padding: "14px 18px", marginBottom: 8,
                      background: isActive ? "#E3E3E3" : "#F7F7F7",
                      border: "none", borderRadius: 10, cursor: "pointer",
                      fontSize: 14, fontWeight: isActive ? 600 : 400, color: "#080908",
                      boxSizing: "border-box", transition: "background 0.1s",
                    }}
                  >
                    <span>{opt.label} <span style={{ fontWeight: 400, color: "#080908" }}>{opt.sub}</span></span>
                    {isActive && (
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0, marginLeft: 8, opacity: 0.45 }}>
                        <path d="M3.69714 14.804L7.69604 18.8029C7.758 18.8653 7.83171 18.9149 7.91293 18.9487C7.99415 18.9826 8.08126 19 8.16924 19C8.25723 19 8.34434 18.9826 8.42556 18.9487C8.50677 18.9149 8.58049 18.8653 8.64245 18.8029C8.70491 18.7409 8.7545 18.6672 8.78833 18.586C8.82217 18.5047 8.83959 18.4176 8.83959 18.3297C8.83959 18.2417 8.82217 18.1546 8.78833 18.0733C8.7545 17.9921 8.70491 17.9184 8.64245 17.8565L5.77657 14.9972H17.5C18.3838 14.9972 19.2314 14.6461 19.8564 14.0212C20.4813 13.3962 20.8324 12.5486 20.8324 11.6648V5.66648C20.8324 5.48972 20.7622 5.3202 20.6372 5.19521C20.5122 5.07022 20.3427 5 20.1659 5C19.9892 5 19.8196 5.07022 19.6947 5.19521C19.5697 5.3202 19.4994 5.48972 19.4994 5.66648V11.6648C19.4994 12.1951 19.2888 12.7037 18.9138 13.0786C18.5389 13.4536 18.0303 13.6643 17.5 13.6643H5.77657L8.64245 10.8051C8.76795 10.6796 8.83845 10.5093 8.83845 10.3319C8.83845 10.1544 8.76795 9.98416 8.64245 9.85866C8.51694 9.73316 8.34673 9.66265 8.16924 9.66265C7.99176 9.66265 7.82154 9.73316 7.69604 9.85866L3.69714 13.8576C3.63468 13.9195 3.58509 13.9932 3.55126 14.0744C3.51742 14.1557 3.5 14.2428 3.5 14.3308C3.5 14.4187 3.51742 14.5059 3.55126 14.5871C3.58509 14.6683 3.63468 14.742 3.69714 14.804Z" fill="black"/>
                      </svg>
                    )}
                  </div>
                );
              })}
            </div>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginTop: 10 }}>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>↑↓ to navigate</span>
              <span style={{ fontSize: 12, color: "#CFCFD1" }}>·</span>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>Enter to select</span>
            </div>
          </div>
        </div>
      )}

      {/* Card picker — pinned at the bottom (AmEx only, after upload prep) */}
      {isNoFeedAccount && prepDone && line4aDone && !cardChosen && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <div style={{
              background: "#FFFFFF",
              border: "1px solid #E9E9EB",
              borderRadius: 8,
              padding: "24px 24px 16px",
              width: "100%",
              boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04)",
            }}>
              <p style={{ fontSize: 14, fontWeight: 500, color: "#080908", marginBottom: 16, marginTop: 0 }}>We've detected multiple credit cards in the bank statement. Which card would you like to reconcile?</p>
              {cardOptions.map((opt, i) => {
                const isActive = i === highlightedCard;
                return (
                  <div
                    key={opt.key}
                    onClick={() => setCardChosen(opt)}
                    onMouseEnter={() => setHighlightedCard(i)}
                    style={{
                      display: "flex", alignItems: "center", justifyContent: "space-between",
                      width: "100%", padding: "14px 18px", marginBottom: 8,
                      background: isActive ? "#E3E3E3" : "#F7F7F7",
                      border: "none", borderRadius: 10, cursor: "pointer",
                      fontSize: 14, fontWeight: isActive ? 600 : 400, color: "#080908",
                      boxSizing: "border-box", transition: "background 0.1s",
                    }}
                  >
                    <span>{opt.label}</span>
                    {isActive && (
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0, marginLeft: 8, opacity: 0.45 }}>
                        <path d="M3.69714 14.804L7.69604 18.8029C7.758 18.8653 7.83171 18.9149 7.91293 18.9487C7.99415 18.9826 8.08126 19 8.16924 19C8.25723 19 8.34434 18.9826 8.42556 18.9487C8.50677 18.9149 8.58049 18.8653 8.64245 18.8029C8.70491 18.7409 8.7545 18.6672 8.78833 18.586C8.82217 18.5047 8.83959 18.4176 8.83959 18.3297C8.83959 18.2417 8.82217 18.1546 8.78833 18.0733C8.7545 17.9921 8.70491 17.9184 8.64245 17.8565L5.77657 14.9972H17.5C18.3838 14.9972 19.2314 14.6461 19.8564 14.0212C20.4813 13.3962 20.8324 12.5486 20.8324 11.6648V5.66648C20.8324 5.48972 20.7622 5.3202 20.6372 5.19521C20.5122 5.07022 20.3427 5 20.1659 5C19.9892 5 19.8196 5.07022 19.6947 5.19521C19.5697 5.3202 19.4994 5.48972 19.4994 5.66648V11.6648C19.4994 12.1951 19.2888 12.7037 18.9138 13.0786C18.5389 13.4536 18.0303 13.6643 17.5 13.6643H5.77657L8.64245 10.8051C8.76795 10.6796 8.83845 10.5093 8.83845 10.3319C8.83845 10.1544 8.76795 9.98416 8.64245 9.85866C8.51694 9.73316 8.34673 9.66265 8.16924 9.66265C7.99176 9.66265 7.82154 9.73316 7.69604 9.85866L3.69714 13.8576C3.63468 13.9195 3.58509 13.9932 3.55126 14.0744C3.51742 14.1557 3.5 14.2428 3.5 14.3308C3.5 14.4187 3.51742 14.5059 3.55126 14.5871C3.58509 14.6683 3.63468 14.742 3.69714 14.804Z" fill="black"/>
                      </svg>
                    )}
                  </div>
                );
              })}
            </div>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginTop: 10 }}>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>↑↓ to navigate</span>
              <span style={{ fontSize: 12, color: "#CFCFD1" }}>·</span>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>Enter to select</span>
            </div>
          </div>
        </div>
      )}

      {/* Upload card — pinned at the bottom */}
      {!clientUpload && line3Done && (!isNoFeedAccount || line3cDone) && !uploadedFiles && !reuploadPhase && !replaceStatementMode && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <UploadCard
                onFileSelected={handleFileSelected}
                onFilesSelected={handleFileSelected}
                onOpenAllDocs={() => setAllDocsOpen(true)}
                preselectedFiles={preselectedDocs}
                suggestedFiles={effectiveAccountName ? (() => {
                  const baseName = {
                    "Lloyds Bank - Business":       "lloyds-bank",
                    "Lloyds Bank - Operations GBP": "lloyds-operations",
                    "HSBC - Business Transactions": "hsbc-business",
                    "Barclays - Operations":        "barclays-operations",
                    "American Express OP GBP":      "amex-op",
                    "Mastercard Business":          "mastercard-business",
                  }[effectiveAccountName];
                  if (!baseName) return [];
                  return [
                    { name: `${baseName}-statement-apr2026.csv`, date: "Uploaded 4 Apr at 15:32 · Client · Sarah Thompson" },
                    { name: `${baseName}-statement-mar2026.csv`, date: "Uploaded 3 Mar at 09:14 · Client · Sarah Thompson" },
                  ];
                })() : []}
              />
          </div>
        </div>
      )}

      {/* Re-upload card — pinned at the bottom */}
      {reuploadPhase && !uploadedFiles && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <UploadCard onFileSelected={file => { handleFileSelected(file); setReuploadPhase(false); }} onOpenAllDocs={() => setAllDocsOpen(true)} />
          </div>
        </div>
      )}

      {/* Replace statement upload — pinned at the bottom */}
      {replaceStatementMode && replaceRespDone && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <UploadCard
              title="New statement"
              onFileSelected={file => {
                setReplaceStatementMode(false);
                setUploadedFiles([{ name: file.name, type: file.type }]);
                setPreviewUrl(null);
                setPrepDone(false);
                setStartClicked(false);
                setStepStatuses([]);
                setStepSubtexts([]);
                setResultsVisible(false);
                setCanvasReady(false);
              }}
              onOpenAllDocs={() => setAllDocsOpen(true)}
            />
          </div>
        </div>
      )}

      {/* Do you wish to proceed? card — pinned at the bottom */}
      {line5bDone && !startClicked && feedProceedChoice !== "convert" && (
        <div style={{ padding: "28px 24px 24px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <div style={{
              background: "#FFFFFF",
              border: "1px solid #E9E9EB",
              borderRadius: 8,
              padding: "24px 24px 16px",
              width: "100%",
              boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04)",
            }}>
              <p style={{ fontSize: 14, fontWeight: 500, color: "#080908", marginBottom: 16, marginTop: 0 }}>Do you wish to proceed?</p>
              {startOptions.map(({ label, primary }, i) => {
                const isKeyActive = i === highlightedStart;
                return (
                  <div
                    key={label}
                    onClick={() => {
                      if (i === 0) { setStartClicked(true); }
                      else {
                        setChangeFlow(true);
                        setPeriodChosen(null);
                        setCardChosen(null);
                        setHighlightedCard(0);
                        setHighlightedPeriod(0);
                        setUploadedFiles(null);
                        setPrepDone(false);
                        setStartClicked(false);
                      }
                    }}
                    style={{
                      display: "flex", alignItems: "center", justifyContent: "space-between",
                      width: "100%", padding: "14px 18px", marginBottom: 8,
                      background: isKeyActive ? "#E3E3E3" : "#F7F7F7",
                      border: "none", borderRadius: 10, cursor: "pointer",
                      fontSize: 14, fontWeight: isKeyActive ? 600 : 400, color: "#080908",
                      boxSizing: "border-box", transition: "background 0.1s",
                    }}
                    onMouseEnter={e => { if (!isKeyActive) e.currentTarget.style.background = "#F0F0F0"; }}
                    onMouseLeave={e => { if (!isKeyActive) e.currentTarget.style.background = "#F7F7F7"; }}
                  >
                    <span>{label}</span>
                    {isKeyActive && (
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0, marginLeft: 8, opacity: 0.45 }}>
                        <path d="M3.69714 14.804L7.69604 18.8029C7.758 18.8653 7.83171 18.9149 7.91293 18.9487C7.99415 18.9826 8.08126 19 8.16924 19C8.25723 19 8.34434 18.9826 8.42556 18.9487C8.50677 18.9149 8.58049 18.8653 8.64245 18.8029C8.70491 18.7409 8.7545 18.6672 8.78833 18.586C8.82217 18.5047 8.83959 18.4176 8.83959 18.3297C8.83959 18.2417 8.82217 18.1546 8.78833 18.0733C8.7545 17.9921 8.70491 17.9184 8.64245 17.8565L5.77657 14.9972H17.5C18.3838 14.9972 19.2314 14.6461 19.8564 14.0212C20.4813 13.3962 20.8324 12.5486 20.8324 11.6648V5.66648C20.8324 5.48972 20.7622 5.3202 20.6372 5.19521C20.5122 5.07022 20.3427 5 20.1659 5C19.9892 5 19.8196 5.07022 19.6947 5.19521C19.5697 5.3202 19.4994 5.48972 19.4994 5.66648V11.6648C19.4994 12.1951 19.2888 12.7037 18.9138 13.0786C18.5389 13.4536 18.0303 13.6643 17.5 13.6643H5.77657L8.64245 10.8051C8.76795 10.6796 8.83845 10.5093 8.83845 10.3319C8.83845 10.1544 8.76795 9.98416 8.64245 9.85866C8.51694 9.73316 8.34673 9.66265 8.16924 9.66265C7.99176 9.66265 7.82154 9.73316 7.69604 9.85866L3.69714 13.8576C3.63468 13.9195 3.58509 13.9932 3.55126 14.0744C3.51742 14.1557 3.5 14.2428 3.5 14.3308C3.5 14.4187 3.51742 14.5059 3.55126 14.5871C3.58509 14.6683 3.63468 14.742 3.69714 14.804Z" fill="black"/>
                      </svg>
                    )}
                  </div>
                );
              })}
            </div>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginTop: 10 }}>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>↑↓ to navigate</span>
              <span style={{ fontSize: 12, color: "#CFCFD1" }}>·</span>
              <span style={{ fontSize: 12, color: "#8C8C8B" }}>Enter to select</span>
            </div>
          </div>
        </div>
      )}

      {/* Reconciliation in progress box — shimmering label + Stop button */}
      {startClicked && !resultsVisible && (
        <div style={{ padding: "0 24px 20px", flexShrink: 0 }}>
          <div style={{ maxWidth: 680, margin: "0 auto" }}>
            <div style={{ borderRadius: 8, padding: "14px 14px 12px", background: "#FFFFFF", boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04), 0 0 0 1px #E9E9EB" }}>
              <div style={{ display: "flex", alignItems: "center" }}>
                <div style={{ fontSize: 14, lineHeight: "22px", flex: 1 }}>
                  <span style={{ background: "linear-gradient(90deg, #9D9D9E 0%, #9D9D9E 30%, #2A2A2A 50%, #9D9D9E 70%, #9D9D9E 100%)", backgroundSize: "200% auto", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", animation: "textShimmer 2s linear infinite", display: "inline-block" }}>
                    Reconciliation in progress...
                  </span>
                </div>
                <button
                  style={{ display: "inline-flex", alignItems: "center", gap: 6, height: 36, padding: "0 10px", border: "1px solid #E9E9EB", borderRadius: 8, background: "#FFFFFF", cursor: "pointer", fontSize: 13, fontWeight: 500, color: "#080908", flexShrink: 0, boxSizing: "border-box" }}
                  onMouseEnter={e => e.currentTarget.style.background = "#F5F5F5"}
                  onMouseLeave={e => e.currentTarget.style.background = "#FFFFFF"}
                >
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                    <rect x="2" y="2" width="10" height="10" rx="1.5" stroke="#080908" strokeWidth="1.25" />
                  </svg>
                  Stop
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Standalone textarea — visible when no action card is showing and not in thinking/loading phase */}
      {thinkingDone && !((isPicker && line2Done && !accountSelected) || (line5Done && !startClicked) || (line3Done && !uploadedFiles && !reuploadPhase && !resultsVisible) || reuploadPhase || replaceStatementMode || (isNoFeedAccount && line3Done && !feedProceedChoice && !resultsVisible) || (feedProceedChoice === "convert" && uploadedFiles && !resultsVisible) || (uploadedFiles && !prepDone) || (prepDone && !line4Done) || (line4Done && !line5Done) || (startClicked && !resultsVisible) || (line3Trigger && !line3ThinkingDone) || (line3ThinkingDone && !line3Done)) && (
          <div style={{ padding: resultsVisible ? "60px 12px 16px" : "0 12px 16px", flexShrink: 0, background: resultsVisible ? "linear-gradient(to bottom, rgba(251,251,251,0) 0%, rgba(251,251,251,1) 60px)" : undefined, marginTop: resultsVisible ? -60 : 0 }}>
            <div style={{ maxWidth: 680, margin: "0 auto" }}>
              {/* Action buttons — shown when results are visible (sidebar mode), hidden while replace flow is open */}
              {resultsVisible && !replaceStatementMode && (
                <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
                  <button
                    onClick={handleRestart}
                    style={{
                      display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 8,
                      height: 40, padding: "0 16px",
                      border: "1px solid #E9E9EB", borderRadius: 8,
                      background: "#FFFFFF", cursor: "pointer",
                      boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04)",
                      fontSize: 14, fontWeight: 500, color: "#080908",
                    }}
                    onMouseEnter={e => { e.currentTarget.style.background = "#FAFAFA"; e.currentTarget.style.borderColor = "#CFCFD1"; }}
                    onMouseLeave={e => { e.currentTarget.style.background = "#FFFFFF"; e.currentTarget.style.borderColor = "#E9E9EB"; }}
                  >
                    <PlayCircleIcon color="#080908" size={18} />
                    Re-run
                  </button>

                </div>
              )}
              <div style={{
                borderRadius: 8, padding: "14px 14px 12px", background: "#FFFFFF",
                boxShadow: "0 12px 24px 0 rgba(0,0,0,0.04), 0 0 0 1px #E9E9EB",
              }}>
                <textarea
                  value={inputValue}
                  onChange={e => setInputValue(e.target.value)}
                  onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
                  placeholder="Ask for changes or information..."
                  rows={3}
                  style={{ width: "100%", border: "none", outline: "none", resize: "none", fontSize: 14, color: "#080908", lineHeight: "22px", background: "transparent", fontFamily: "'Inter', sans-serif", display: "block" }}
                />
                <div style={{ display: "flex", alignItems: "center", marginTop: 8 }}>
                  {/* Attachment */}
                  <button style={{ width: 32, height: 32, border: "none", background: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: 6, color: "#8C8C8B", padding: 0 }}
                    onMouseEnter={e => e.currentTarget.style.background = "#F5F5F5"}
                    onMouseLeave={e => e.currentTarget.style.background = "none"}
                  >
                    <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                      <path d="M15.5 8.5L8.5 15.5C7.12 16.88 4.88 16.88 3.5 15.5C2.12 14.12 2.12 11.88 3.5 10.5L10.5 3.5C11.33 2.67 12.67 2.67 13.5 3.5C14.33 4.33 14.33 5.67 13.5 6.5L6.5 13.5C6.08 13.92 5.42 13.92 5 13.5C4.58 13.08 4.58 12.42 5 12L11.5 5.5" stroke="currentColor" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  </button>
                  <div style={{ flex: 1 }} />
                  {/* Microphone */}
                  <button style={{ width: 32, height: 32, border: "none", background: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: 6, color: "#8C8C8B", padding: 0 }}
                    onMouseEnter={e => e.currentTarget.style.background = "#F5F5F5"}
                    onMouseLeave={e => e.currentTarget.style.background = "none"}
                  >
                    <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                      <rect x="6" y="1" width="6" height="10" rx="3" stroke="currentColor" strokeWidth="1.25" />
                      <path d="M3 9C3 12.31 5.69 15 9 15C12.31 15 15 12.31 15 9" stroke="currentColor" strokeWidth="1.25" strokeLinecap="round" />
                      <line x1="9" y1="15" x2="9" y2="17" stroke="currentColor" strokeWidth="1.25" strokeLinecap="round" />
                    </svg>
                  </button>
                  {/* Send */}
                  <button onClick={handleSend} style={{ width: 36, height: 36, marginLeft: 6, border: "1px solid #E9E9EB", borderRadius: 10, background: inputValue.trim() ? "#05A105" : "#FAFAFA", cursor: inputValue.trim() ? "pointer" : "default", display: "flex", alignItems: "center", justifyContent: "center", transition: "background 0.15s", padding: 0 }}>
                    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                      <path d="M9.99984 15.8346V4.16797M9.99984 4.16797L4.1665 10.0013M9.99984 4.16797L15.8332 10.0013" stroke={inputValue.trim() ? "#FFFFFF" : "#8C8C8B"} strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  </button>
                </div>
              </div>
            </div>
          </div>
      )}

      </div> {/* end chat area wrapper */}
      </div> {/* end left chat panel */}

      {/* Canvas — slides in from right, pushes chat into sidebar */}
      <div style={{
        position: "absolute",
        top: 16, bottom: 16,
        left: chatWidth + 32,
        right: boxesOpen ? 432 : 16,
        background: "#FFFFFF",
        borderRadius: 8,
        border: "1px solid #ECECEC",
        overflow: "hidden",
        zIndex: 2,
        transform: resultsVisible ? "none" : "translateX(calc(100% + 32px))",
        transition: isDragging ? "none" : "transform 0.72s cubic-bezier(0.16, 1, 0.3, 1), right 0.35s cubic-bezier(0.16, 1, 0.3, 1)",
        willChange: resultsVisible ? "auto" : "transform",
      }}>
        {canvasReady ? (
          <div style={{ animation: "resultsFadeIn 0.4s ease 0.1s both", height: "100%", overflowY: "auto" }}>
            {false ? null : (
              <ResultsPanel
                accountName={effectiveAccountName}
                isCleanReconcile={effectiveIsCleanReconcile || (!allResolved && (resolvedCards.size + ignoredCards.size) >= totalSuggestions)}
                allJustResolved={!allResolved && (resolvedCards.size + ignoredCards.size) >= totalSuggestions}
                onAccountsOverview={() => { const remaining = Math.max(0, totalSuggestions - resolvedCards.size - ignoredCards.size); onClose(true, (resolvedCards.size + ignoredCards.size) >= totalSuggestions, effectiveAccountName, remaining, resolvedCards, ignoredCards); }}
                matchedTotal={reconciledMatchedStr ? parseInt(reconciledMatchedStr.split("/")[1]) || null : null}
                onOpenSpendMoney={(entry, cardIndex) => setSpendMoneySidebar({ ...entry, cardIndex })}
                onOpenBatchDraft={(entry, cardIndex) => setBatchDraftSidebar({ ...entry, cardIndex })}
                resolvedCards={resolvedCards}
                onResolveCard={(idx) => setResolvedCards(prev => new Set([...prev, idx]))}
                ignoredCards={ignoredCards}
                onIgnoreCard={(idx) => setIgnoredCards(prev => new Set([...prev, idx]))}
                onShowToast={(msg) => { setToast(msg); setTimeout(() => setToast(null), 4000); }}
                onAddAuditEntry={addAuditEntry}
                accountStatus={accountStatus}
                boxesOpen={false}
                uploadedFileName={uploadedFiles?.[0]?.name}
              />
            )}
          </div>
        ) : resultsVisible ? <CanvasLoader /> : null}
      </div>

      {/* Suggestions sidebar — floats on gray background, outside the canvas card */}
      {canvasReady && (() => {
          const isHSBCCanvas = effectiveAccountName === "HSBC - Business Transactions";
          // isPreClean: account was already reconciled before opening — no suggestions exist at all
          const isPreClean = effectiveIsCleanReconcile;
          // allJustResolved: user resolved/ignored every suggestion during this session, OR account was already completed on open
          const allJustResolved = (
            (!allResolved && (resolvedCards.size + ignoredCards.size) >= totalSuggestions) ||
            (allResolved && accountStatus === "completed")
          );
          const isClean = isPreClean || allJustResolved; // used by ResultsPanel for chat behaviour

          // Build nav cats — always the full list so resolved items remain visible
          const navCats = isPreClean ? []
            : isHSBCCanvas ? [
              { key: "missing",   label: "Missing entries",  baseIdx:  0, items: [{ contact: "Meridian Freight Ltd" }, { contact: "Hartley & Sons Supplies" }, { contact: "Queensbury Engineering" }, { contact: "Lakewood Solutions" }, { contact: "Pinecroft Consulting" }, { contact: "Ashford & Clarke" }, { contact: "Northgate Financial" }, { contact: "Westbrook Services" }, { contact: "Templeton & Ward" }, { contact: "Greystone Technologies" }, { contact: "Fairfield Logistics" }, { contact: "Coppergate Partners" }, { contact: "Riverside Digital" }, { contact: "Whitmore Agency" }, { contact: "Stonegate Ventures" }, { contact: "Elmwood Trading" }, { contact: "Bridgewater Associates" }, { contact: "Redwood Consulting" }] },
              { key: "anomaly",   label: "Anomalies",        baseIdx: 18, items: [{ contact: "Premier Office Supplies" }, { contact: "Highfield Analytics" }, { contact: "Oakwood Research" }, { contact: "Silverstone Group" }, { contact: "Blackthorn Events" }, { contact: "Mapleton Industries" }, { contact: "Greenfield Partners" }, { contact: "Haverstock Ltd" }, { contact: "Bramblewood Services" }, { contact: "Thornfield Capital" }, { contact: "Clearwater Tech" }, { contact: "Longbridge Agency" }] },
              { key: "duplicate", label: "Duplicates",       baseIdx: 30, items: [{ contact: "Meridian Freight Ltd" }, { contact: "Premier Office Supplies" }, { contact: "Hartley & Sons Supplies" }, { contact: "Highfield Analytics" }, { contact: "Westbrook Services" }, { contact: "Oakwood Research" }, { contact: "Coppergate Partners" }, { contact: "Silverstone Group" }, { contact: "Riverside Digital" }, { contact: "Mapleton Industries" }] },
              { key: "date",      label: "Date differences", baseIdx: 40, items: [{ contact: "Ashford & Clarke" }, { contact: "Northgate Financial" }, { contact: "Blackthorn Events" }, { contact: "Templeton & Ward" }, { contact: "Greystone Technologies" }, { contact: "Haverstock Ltd" }, { contact: "Fairfield Logistics" }, { contact: "Bramblewood Services" }, { contact: "Stonegate Ventures" }, { contact: "Elmwood Trading" }] },
              { key: "omitted",   label: "Omitted",          baseIdx: 50, items: [{ contact: "Internal Transfer" }, { contact: "Standing Order — HMRC" }, { contact: "Direct Debit — Utilities" }, { contact: "Payroll Batch" }, { contact: "Bank Charges" }] },
              { key: "general",   label: "General",          baseIdx: 55, items: [{ contact: "Unclassified Entry A" }, { contact: "Unclassified Entry B" }, { contact: "Unclassified Entry C" }] },
            ]
            : effectiveAccountName === "Barclays - Operations" ? [
              { key: "missing", label: "Missing entries", baseIdx: 0, items: [{ contact: "Hillcrest Imports" }, { contact: "NorthStar Media" }] },
              { key: "anomaly", label: "Anomalies",       baseIdx: 2, items: [{ contact: "Parkway Solutions" }] },
              { key: "omitted", label: "Omitted",         baseIdx: 3, items: [{ contact: "Central Freight Co" }] },
              { key: "general", label: "General",         baseIdx: 4, items: [{ contact: "Unclassified" }] },
            ]
            : effectiveAccountName === "American Express OP GBP" ? [
              { key: "missing",   label: "Missing entries",   baseIdx: 0, items: [{ contact: "Vantage Digital" }, { contact: "Oxton Supply Co" }] },
              { key: "date",      label: "Date differences",  baseIdx: 2, items: [{ contact: "Apex Consulting" }, { contact: "BlueSky Events" }] },
              { key: "duplicate", label: "Duplicates",        baseIdx: 4, items: [{ contact: "Nexcore Technologies" }] },
              { key: "omitted",   label: "Omitted",           baseIdx: 5, items: [{ contact: "Stratton Media Group" }] },
              { key: "anomaly",   label: "Anomalies",         baseIdx: 6, items: [{ contact: "Clearfield Associates" }] },
              { key: "general",   label: "General",           baseIdx: 7, items: [{ contact: "Unclassified" }] },
            ]
            : effectiveAccountName === "Mastercard Business" ? [
              { key: "missing",   label: "Missing entries", baseIdx: 0, items: [{ contact: "Harrison & Webb" }] },
              { key: "anomaly",   label: "Anomalies",       baseIdx: 1, items: [{ contact: "Clearpoint Services" }] },
              { key: "duplicate", label: "Duplicates",      baseIdx: 2, items: [{ contact: "Harrison & Webb" }] },
            ]
            : [
              { key: "missing",   label: "Missing entries",   baseIdx: 0, items: [{ contact: "Yorkshire Tea Estates" }, { contact: "Clifton & Harrow Supplies" }, { contact: "Meridian Office Solutions" }] },
              { key: "anomaly",   label: "Anomalies",         baseIdx: 3, items: [{ contact: "Bakery & Food Supplies" }] },
              { key: "duplicate", label: "Duplicates",        baseIdx: 4, items: [{ contact: "Yorkshire Tea Estates" }] },
              { key: "date",      label: "Date differences",  baseIdx: 5, items: [{ contact: "Direct Expenses" }] },
              { key: "omitted",   label: "Omitted",           baseIdx: 6, items: [{ contact: "Internal Transfer" }] },
              { key: "general",   label: "General",           baseIdx: 7, items: [{ contact: "Unclassified" }] },
            ];
          const totalSugg = navCats.reduce((s, c) => s + c.items.length, 0);
          const cats = navCats.map(c => ({ label: c.label, count: c.items.length }));
          const matchedTotalNum = reconciledMatchedStr ? parseInt(reconciledMatchedStr.split("/")[1]) || null : null;

          // Hide boxes only for pre-reconciled accounts (no suggestions to show)
          if (isPreClean) return null;
          return (
            <div style={{
              position: "absolute",
              top: 16, bottom: 16, right: 16,
              width: 400,
              zIndex: 3,
              display: "flex",
              flexDirection: "column",
              fontFamily: "'Inter', sans-serif",
              transform: boxesOpen ? "translateX(0)" : "translateX(calc(100% + 32px))",
              transition: "transform 0.35s cubic-bezier(0.16, 1, 0.3, 1)",
              pointerEvents: boxesOpen ? "auto" : "none",
            }}>
              <SuggestionsBox
                isCleanReconcile={false}
                allJustResolved={allJustResolved}
                accountStatus={accountStatus}
                resolvedCount={resolvedCards.size + ignoredCards.size}
                totalSuggestions={totalSugg}
                matchedTotal={matchedTotalNum}
                navCategories={navCats}
                resolvedCards={resolvedCards}
                ignoredCards={ignoredCards}
              />
            </div>
          );
        })()}

      {/* Drag handle — invisible hit area with a centered notch on hover */}
      {resultsVisible && (
        <div
          onMouseDown={handleDragStart}
          style={{
            position: "absolute",
            top: 0,
            bottom: 0,
            left: chatWidth + 27,
            width: 12,
            cursor: "col-resize",
            zIndex: 10,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
          onMouseEnter={e => { const notch = e.currentTarget.firstChild; if (notch) notch.style.opacity = "1"; }}
          onMouseLeave={e => { if (!isDragging) { const notch = e.currentTarget.firstChild; if (notch) notch.style.opacity = "0"; } }}
        >
          <div style={{
            width: 5,
            height: 56,
            borderRadius: 2.5,
            background: "#7C7C7C",
            opacity: isDragging ? 1 : 0,
            transition: "opacity 0.15s",
            pointerEvents: "none",
          }} />
        </div>
      )}

      </div> {/* end content area */}

      {/* All documents sidebar — top level so it covers the topbar */}
      {allDocsOpen && (
        <AllDocumentsSidebar
          onClose={() => setAllDocsOpen(false)}
          onSelect={docs => { setPreselectedDocs(docs.map(d => ({ name: d.name, type: "text/csv" }))); setAllDocsOpen(false); }}
        />
      )}

      {/* Spend money sidebar — rendered here (top level) so it's above topbar and chat panel */}
      {spendMoneySidebar && (
        <>
          <div onClick={() => setSpendMoneySidebar(null)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.35)", zIndex: 200 }} />
          <SpendMoneySidebar
            contact={spendMoneySidebar.contact}
            amount={spendMoneySidebar.amount}
            date={spendMoneySidebar.date}
            onClose={() => setSpendMoneySidebar(null)}
            onPublish={(data) => {
              if (spendMoneySidebar.cardIndex != null) {
                setResolvedCards(prev => new Set([...prev, spendMoneySidebar.cardIndex]));
              }
              const d = data || {};
              addAuditEntryRef.current?.("Spend money created", `Spend money created for ${d.amount || spendMoneySidebar.amount || ""} dated ${d.date || ""} for "${d.contact || spendMoneySidebar.contact || ""}", account "${d.account || "Software Subscriptions"}", tax "${d.tax || "No VAT"}".`, "#05A105");
              setToast("Spend money created and published successfully");
              setTimeout(() => setToast(null), 4000);
            }}
          />
        </>
      )}

      {/* Batch draft sidebar */}
      {batchDraftSidebar && (
        <>
          <BatchDraftSidebar
            contact={batchDraftSidebar.contact}
            amount={batchDraftSidebar.amount}
            date={batchDraftSidebar.date}
            fileName={batchDraftSidebar.fileAction}
            onClose={() => setBatchDraftSidebar(null)}
            onConfirm={() => {
              if (batchDraftSidebar.cardIndex != null) {
                setResolvedCards(prev => new Set([...prev, batchDraftSidebar.cardIndex]));
              }
              setToast("Document confirmed and published successfully");
              setTimeout(() => setToast(null), 4000);
            }}
          />
        </>
      )}

      {/* Success toast */}
      {toast && (
        <div style={{
          position: "fixed", top: 24, left: "50%", transform: "translateX(-50%)",
          background: "#05A105", color: "#FFFFFF", padding: "12px 20px",
          borderRadius: 10, fontSize: 14, fontWeight: 500,
          display: "flex", alignItems: "center", gap: 10,
          zIndex: 300, animation: "toastIn 0.35s ease",
          fontFamily: "'Inter', sans-serif",
        }}>
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none" style={{ flexShrink: 0 }}>
            <path d="M10 18.3333C14.6024 18.3333 18.3333 14.6024 18.3333 10C18.3333 5.39763 14.6024 1.66667 10 1.66667C5.39763 1.66667 1.66667 5.39763 1.66667 10C1.66667 14.6024 5.39763 18.3333 10 18.3333Z" fill="rgba(255,255,255,0.25)"/>
            <path d="M6.66667 10L8.88889 12.2222L13.3333 7.77778" stroke="#FFFFFF" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
          {toast}
        </div>
      )}
    </div>
  );
}

// ── TopBar component (from TopBar.jsx) ────────────────────────────────────────
const PERIOD_OPTIONS = [
  "September 2025", "October 2025", "November 2025", "December 2025",
  "January 2026", "February 2026", "March 2026", "April 2026",
];

function TopBar({
  contextLabel = "Month-end close",
  period = "April 2026",
  syncStatus = "Last synced 32 minutes ago",
  syncLabel = "Sync with Xero",
  onPeriodChange,
  onSyncClick,
  syncing = false,
}) {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    if (!dropdownOpen) return;
    const handler = e => { if (ref.current && !ref.current.contains(e.target)) setDropdownOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [dropdownOpen]);

  return (
    <div style={{ height: 60, background: "#FFFFFF", borderBottom: "1px solid #E9E9EB", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 24px 0 16px", flexShrink: 0 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <span style={{ fontSize: 14, fontWeight: 500, color: "#7b7b7b" }}>{contextLabel}</span>
        <div ref={ref} style={{ position: "relative" }}>
        <button onClick={() => setDropdownOpen(v => !v)} style={{ display: "flex", alignItems: "center", gap: 6, padding: "0 10px", height: 32, border: "1px solid #E9E9EB", borderRadius: 6, background: "#FFFFFF", cursor: "pointer", fontSize: 14, fontWeight: 500, color: "#080908" }}
          onMouseEnter={e => e.currentTarget.style.borderColor = "#CFCFD1"}
          onMouseLeave={e => e.currentTarget.style.borderColor = "#E9E9EB"}>
          {period} <Chevron up={dropdownOpen} color="#080908" size={13} />
        </button>
        {dropdownOpen && (
          <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, background: "#FFFFFF", border: "1px solid #E9E9EB", borderRadius: 8, boxShadow: "0 4px 16px rgba(0,0,0,0.1)", zIndex: 200, minWidth: 180, overflow: "hidden" }}>
            {PERIOD_OPTIONS.map(p => (
              <button key={p} onClick={() => { onPeriodChange?.(p); setDropdownOpen(false); }}
                style={{ display: "block", width: "100%", padding: "9px 14px", border: "none", background: p === period ? "#F5F5F5" : "#FFFFFF", cursor: "pointer", fontSize: 14, color: "#080908", textAlign: "left", fontWeight: p === period ? 500 : 400 }}
                onMouseEnter={e => { if (p !== period) e.currentTarget.style.background = "#FAFAFA"; }}
                onMouseLeave={e => { if (p !== period) e.currentTarget.style.background = "#FFFFFF"; }}>
                {p}
              </button>
            ))}
          </div>
        )}
        </div>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <span style={{ fontSize: 14, color: "#8C8C8B" }}>{syncStatus}</span>
        <button onClick={syncing ? undefined : onSyncClick}
          style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "0 12px", height: 36, border: "1px solid #E9E9EB", borderRadius: 6, background: syncing ? "#FAFAFA" : "#FFFFFF", cursor: syncing ? "default" : "pointer", fontSize: 14, fontWeight: 500, color: "#080908", transition: "background 0.15s" }}
          onMouseEnter={e => { if (!syncing) { e.currentTarget.style.borderColor = "#CFCFD1"; e.currentTarget.style.background = "#FAFAFA"; } }}
          onMouseLeave={e => { if (!syncing) { e.currentTarget.style.borderColor = "#E9E9EB"; e.currentTarget.style.background = "#FFFFFF"; } }}>
          {syncing && (
            <svg width="14" height="14" viewBox="0 0 36 36" fill="none" style={{ animation: "spin 0.75s linear infinite", flexShrink: 0 }}>
              <path d="M18 3A15 15 0 1 1 3 18" stroke="#05A105" strokeWidth="3" strokeLinecap="round"/>
            </svg>
          )}
          {syncing ? "Syncing with Xero" : syncLabel}
        </button>
      </div>
    </div>
  );
}

// ── Button components (from Buttons.jsx) ──────────────────────────────────────
function PrimaryButton({ children, icon, iconLeft, onClick, disabled = false, style = {} }) {
  return (
    <button onClick={disabled ? undefined : onClick} disabled={disabled} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 16px", background: disabled ? "#F5F5F5" : "#05A105", color: disabled ? "#9D9D9E" : "#FFFFFF", border: "none", borderRadius: 8, cursor: disabled ? "default" : "pointer", fontSize: 14, fontWeight: 500, fontFamily: "'Inter', sans-serif", transition: "background 0.15s ease", ...style }}
      onMouseEnter={e => { if (!disabled) e.currentTarget.style.background = "#058F05"; }}
      onMouseLeave={e => { if (!disabled) e.currentTarget.style.background = "#05A105"; }}>
      {iconLeft}{children}{icon}
    </button>
  );
}

function SecondaryButton({ children, icon, iconLeft, onClick, disabled = false, style = {}, onMouseEnter, onMouseLeave }) {
  const defaultEnter = e => { if (!disabled) { e.currentTarget.style.borderColor = "#CFCFD1"; e.currentTarget.style.background = "#FAFAFA"; } };
  const defaultLeave = e => { if (!disabled) { e.currentTarget.style.borderColor = "#E9E9EB"; e.currentTarget.style.background = "#FFFFFF"; } };
  return (
    <button onClick={disabled ? undefined : onClick} disabled={disabled} style={{ display: "inline-flex", alignItems: "center", gap: 6, padding: "10px 12px", background: disabled ? "#F5F5F5" : "#FFFFFF", color: disabled ? "#9D9D9E" : "#080908", border: `1px solid ${disabled ? "#F5F5F5" : "#E9E9EB"}`, borderRadius: 6, cursor: disabled ? "default" : "pointer", fontSize: 14, fontWeight: 500, fontFamily: "'Inter', sans-serif", whiteSpace: "nowrap", transition: "all 0.15s ease", ...style }}
      onMouseEnter={onMouseEnter || defaultEnter}
      onMouseLeave={onMouseLeave || defaultLeave}>
      {iconLeft}{children}{icon}
    </button>
  );
}

// ── Widgets components (from Widgets.jsx) ─────────────────────────────────────
function StatsWidget({ label, value, progress = 0 }) {
  return (
    <div style={{ background: "#FFFFFF", border: "1px solid #E9E9EB", borderRadius: 8, padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
      <ProgressRing progress={progress} size={40} strokeWidth={3} />
      <div>
        <div style={{ fontSize: 14, color: "#8C8C8B", marginBottom: 2 }}>{label}</div>
        <div style={{ fontSize: 18, fontWeight: 500, color: "#080908" }}>{value}</div>
      </div>
    </div>
  );
}

function StatsRow({ items = [], columns }) {
  const cols = columns || items.length || 1;
  return (
    <div style={{ display: "grid", gridTemplateColumns: `repeat(${cols}, 1fr)`, gap: 12 }}>
      {items.map((item, i) => <StatsWidget key={i} label={item.label} value={item.value} progress={item.progress} />)}
    </div>
  );
}

// ── DataTable component (from Tables.jsx) ─────────────────────────────────────
function DataTable({ title, columns = [], rows = [], footerLabel, footerRow, onRowClick, containerStyle = {} }) {
  const [hovered, setHovered] = useState(null);
  const gridTemplate = columns.map(c => c.width || "1fr").join(" ");
  return (
    <div style={{ background: "#FFFFFF", border: "1px solid #E9E9EB", borderRadius: 8, overflow: "hidden", fontFamily: "'Inter', sans-serif", ...containerStyle }}>
      {title && <div style={{ padding: "16px 16px 14px", borderBottom: "1px solid #E9E9EB" }}><span style={{ fontSize: 18, fontWeight: 500, color: "#080908" }}>{title}</span></div>}
      <div style={{ display: "grid", gridTemplateColumns: gridTemplate, borderBottom: "1px solid #E9E9EB", background: "#FFFFFF" }}>
        {columns.map((col, ci) => (
          <div key={col.key} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 14, fontWeight: 400, color: "#8C8C8B", padding: col.cellPadding ? col.cellPadding.replace("14px", "10px") : "10px 16px", borderRight: ci < columns.length - 1 ? "1px solid #E9E9EB" : "none", justifyContent: col.align === "right" ? "flex-end" : "flex-start" }}>
            {col.label}{col.sortable && <SortIcon />}
          </div>
        ))}
      </div>
      {rows.map((row, ri) => (
        <div key={ri} onClick={() => onRowClick?.(row, ri)} onMouseEnter={() => setHovered(ri)} onMouseLeave={() => setHovered(null)}
          style={{ display: "grid", gridTemplateColumns: gridTemplate, borderBottom: "1px solid #E9E9EB", background: hovered === ri ? "#FAFAFA" : "#FFFFFF", transition: "background 0.1s", cursor: onRowClick ? "pointer" : "default" }}>
          {columns.map((col, ci) => (
            <div key={col.key} style={{ display: "flex", alignItems: "center", justifyContent: col.align === "right" ? "flex-end" : "flex-start", fontSize: 14, color: "#080908", padding: col.cellPadding || "14px 16px", borderRight: ci < columns.length - 1 ? "1px solid #E9E9EB" : "none", overflow: "hidden", minWidth: 0, whiteSpace: "nowrap" }}>
              {col.render ? col.render(row[col.key], row, ri) : row[col.key]}
            </div>
          ))}
        </div>
      ))}
      {footerRow && (
        <div style={{ display: "grid", gridTemplateColumns: gridTemplate, background: "#FAFAFA" }}>
          {columns.map((col, ci) => (
            <div key={col.key} style={{ display: "flex", alignItems: "center", justifyContent: col.align === "right" ? "flex-end" : "flex-start", fontSize: 14, fontWeight: 600, color: "#080908", padding: "14px 16px", borderRight: ci < columns.length - 1 ? "1px solid #E9E9EB" : "none" }}>
              {footerRow[col.key] ?? ""}
            </div>
          ))}
        </div>
      )}
      {footerLabel && <div style={{ padding: "12px 16px", fontSize: 14, color: "#8C8C8B", borderTop: "1px solid #E9E9EB" }}>{footerLabel}</div>}
    </div>
  );
}


